import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  START = 'START',
  PLAYING = 'PLAYING',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER'
}

export interface PhysicsConfig {
  gravity: number;
  jumpStrength: number;
  pipeSpeed: number;
  gapSize: number;
  spawnRate: number; // Frames between spawns
}

export interface Perk {
  id: string;
  name: string;
  description: string;
  rarity: 'common' | 'rare' | 'legendary';
  apply: (config: PhysicsConfig) => PhysicsConfig;
  icon: string; // Emoji char
}

export interface PipeData {
  id: number;
  x: number;
  topHeight: number;
  passed: boolean;
}

export interface BirdState {
  y: number;
  velocity: number;
  rotation: number;
  isShielded: boolean;
  scale: number;
}

import { PhysicsConfig, Perk } from './types';

export const GAME_WIDTH = 400;
export const GAME_HEIGHT = 600;
export const BIRD_SIZE = 30;
export const PIPE_WIDTH = 50;
export const GROUND_HEIGHT = 40;

export const INITIAL_PHYSICS: PhysicsConfig = {
  gravity: 0.5,
  jumpStrength: -8,
  pipeSpeed: 3,
  gapSize: 160,
  spawnRate: 100,
};

export const LEVEL_UP_INTERVAL = 5; // Pipes needed to level up

export const AVAILABLE_PERKS: Perk[] = [
  {
    id: 'feather_weight',
    name: 'Feather Weight',
    description: 'Gravity is reduced by 20%. Floaty!',
    rarity: 'common',
    icon: '🪶',
    apply: (cfg) => ({ ...cfg, gravity: cfg.gravity * 0.8 }),
  },
  {
