  },
  {
    id: 'tiny_mode',
    name: 'Tiny Mode',
    description: 'Visual only: The bird is smaller.',
    rarity: 'legendary',
    icon: '🤏',
    apply: (cfg) => ({ ...cfg }), // Handled in render logic via state check
  },
  {
    id: 'zen_mode',
    name: 'Zen Mode',
    description: 'Everything slows down by 15%.',
    rarity: 'legendary',
    icon: '🧘',
    apply: (cfg) => ({ 
      ...cfg, 
      pipeSpeed: cfg.pipeSpeed * 0.85, 
      gravity: cfg.gravity * 0.85,
