    }),
  },
];

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, PhysicsConfig, PipeData, BirdState, Perk } from '../types';
import { 
  GAME_WIDTH, 
  GAME_HEIGHT, 
  INITIAL_PHYSICS, 
  BIRD_SIZE, 
  PIPE_WIDTH, 
  GROUND_HEIGHT, 
  AVAILABLE_PERKS,
  LEVEL_UP_INTERVAL
} from '../constants';

const GameEngine: React.FC = () => {
  // Game State
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [score, setScore] = useState(0);
  const [level, setLevel] = useState(1);
  const [highScore, setHighScore] = useState(0);
  const [activePerks, setActivePerks] = useState<Perk[]>([]);
  const [offeredPerks, setOfferedPerks] = useState<Perk[]>([]);

  // Physics State (Refs for performance)
  const birdRef = useRef<BirdState>({ y: GAME_HEIGHT / 2, velocity: 0, rotation: 0, isShielded: false, scale: 1 });
  const pipesRef = useRef<PipeData[]>([]);
  const frameRef = useRef<number>(0);
  const physicsConfigRef = useRef<PhysicsConfig>({ ...INITIAL_PHYSICS });
  const lastTimeRef = useRef<number>(0);
  const progressRef = useRef<number>(0); // Tracks progress to next level

  // Force render helper for physics updates that need visual changes
  const [, setTick] = useState(0);

  const resetGame = () => {
    birdRef.current = { y: GAME_HEIGHT / 2, velocity: 0, rotation: 0, isShielded: false, scale: 1 };
    pipesRef.current = [];
    physicsConfigRef.current = { ...INITIAL_PHYSICS };
    setScore(0);
    setLevel(1);
    setActivePerks([]);
    progressRef.current = 0;
    setGameState(GameState.START);
  };

  const jump = useCallback(() => {
    if (gameState === GameState.PLAYING) {
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
    } else if (gameState === GameState.START) {
      setGameState(GameState.PLAYING);
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
    }
  }, [gameState]);

  const handleLevelUp = () => {
    setGameState(GameState.LEVEL_UP);

    // Select 3 random unique perks
    const shuffled = [...AVAILABLE_PERKS].sort(() => 0.5 - Math.random());
    setOfferedPerks(shuffled.slice(0, 3));
  };

  const selectPerk = (perk: Perk) => {
    setActivePerks(prev => [...prev, perk]);
    physicsConfigRef.current = perk.apply(physicsConfigRef.current);

    // Special case for Tiny Mode which isn't just physics
    if (perk.id === 'tiny_mode') {
      birdRef.current.scale = 0.6;
    }

    setGameState(GameState.PLAYING);
    lastTimeRef.current = performance.now(); // Reset delta timer
  };

  // Main Game Loop
  const update = useCallback((time: number) => {
    if (gameState !== GameState.PLAYING) {
      if (gameState === GameState.START) {
        // Hover animation
        birdRef.current.y = (GAME_HEIGHT / 2) + Math.sin(time / 300) * 10;
        setTick(t => t + 1);
        frameRef.current = requestAnimationFrame(update);
      }
      return;
    }

    const dt = Math.min((time - lastTimeRef.current) / 16.67, 2); // Cap delta time
    lastTimeRef.current = time;

    const config = physicsConfigRef.current;
    const bird = birdRef.current;
    const pipes = pipesRef.current;

    // Apply Gravity
    bird.velocity += config.gravity * dt;
    bird.y += bird.velocity * dt;

    // Rotation calculation
    bird.rotation = Math.min(Math.max(bird.velocity * 3, -25), 90);

    // Pipe Spawning
    const spawnThreshold = config.spawnRate;
    // Use a simpler distance based spawning to avoid frame rate dependency issues
    const lastPipe = pipes[pipes.length - 1];
    if (!lastPipe || (GAME_WIDTH - lastPipe.x) >= (config.pipeSpeed * spawnThreshold / 3)) { // Approximate logic
       // Actually let's strictly use distance
       if (!lastPipe || (GAME_WIDTH - lastPipe.x) > 220) { // Distance between pipes
          const minPipeHeight = 50;
          const maxPipeHeight = GAME_HEIGHT - GROUND_HEIGHT - config.gapSize - minPipeHeight;
          const randomHeight = Math.floor(Math.random() * (maxPipeHeight - minPipeHeight + 1)) + minPipeHeight;

          pipes.push({
            id: Date.now(),
            x: GAME_WIDTH,
            topHeight: randomHeight,
            passed: false
          });
       }
    }

    // Update Pipes
    for (let i = pipes.length - 1; i >= 0; i--) {
      const p = pipes[i];
      p.x -= config.pipeSpeed * dt;

      // Remove off-screen pipes
      if (p.x + PIPE_WIDTH < 0) {
        pipes.splice(i, 1);
        continue;
      }

      // Check for Score/Level Up
      if (!p.passed && p.x + PIPE_WIDTH < (GAME_WIDTH / 2) - (BIRD_SIZE / 2)) {
        p.passed = true;
        setScore(s => {
          const newScore = s + 1;
          progressRef.current += 1;
          if (progressRef.current >= LEVEL_UP_INTERVAL) {
             progressRef.current = 0;
             setLevel(l => l + 1);
             // Trigger Level Up on next render
             setTimeout(handleLevelUp, 0); 
          }
          return newScore;
        });
      }

      // Collision Detection
      const birdRadius = (BIRD_SIZE * bird.scale) / 2; // Hitbox slightly smaller
      const birdLeft = (GAME_WIDTH / 2) - birdRadius + 4; // Add padding
      const birdRight = (GAME_WIDTH / 2) + birdRadius - 4;
      const birdTop = bird.y - birdRadius + 4;
      const birdBottom = bird.y + birdRadius - 4;

      const pipeLeft = p.x;
      const pipeRight = p.x + PIPE_WIDTH;

      const hitTopPipe = birdTop < p.topHeight;
      const hitBottomPipe = birdBottom > p.topHeight + config.gapSize;

      // Check horizontal overlap
      if (birdRight > pipeLeft && birdLeft < pipeRight) {
        if (hitTopPipe || hitBottomPipe) {
          setGameState(GameState.GAME_OVER);
          setHighScore(prev => Math.max(prev, score));
        }
      }
    }

    // Ground/Ceiling Collision
    if (bird.y + (BIRD_SIZE * bird.scale) / 2 >= GAME_HEIGHT - GROUND_HEIGHT) {
      setGameState(GameState.GAME_OVER);
      setHighScore(prev => Math.max(prev, score));
    }
    // Optional: Ceiling collision kills? Or just clamps? Let's just clamp top.
    if (bird.y < 0) {
      bird.y = 0;
      bird.velocity = 0;
    }

    setTick(time); // Trigger render
    frameRef.current = requestAnimationFrame(update);

  }, [gameState, score]);

  useEffect(() => {
    lastTimeRef.current = performance.now();
    frameRef.current = requestAnimationFrame(update);
    return () => cancelAnimationFrame(frameRef.current);
  }, [update]);

  // Input Listeners
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') jump();
    };
    const handleTouch = (e: TouchEvent) => {
      // Prevent default to stop scrolling/zooming
      // e.preventDefault(); // Moved to passive: false in effect options if possible, but React handles events differently.
      jump();
    };

    window.addEventListener('keydown', handleKeyDown);
    // Use window listener for touch to ensure it catches everywhere
    window.addEventListener('touchstart', handleTouch);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('touchstart', handleTouch);
    };
  }, [jump]);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-slate-950 p-4">

      {/* Game Container */}
      <div 
        className="relative overflow-hidden shadow-2xl rounded-lg ring-4 ring-slate-800"
        style={{ width: GAME_WIDTH, height: GAME_HEIGHT, background: 'linear-gradient(to bottom, #4facfe 0%, #00f2fe 100%)' }}
        onMouseDown={jump}
      >
        {/* Background Clouds (Static for now, could animate) */}
        <div className="absolute top-20 left-10 opacity-50 text-white text-6xl select-none">☁️</div>
        <div className="absolute top-40 left-60 opacity-40 text-white text-5xl select-none">☁️</div>
        <div className="absolute top-10 left-80 opacity-60 text-white text-4xl select-none">☁️</div>

        {/* Pipes */}
        {pipesRef.current.map(pipe => (
          <React.Fragment key={pipe.id}>
            {/* Top Pipe */}
            <div 
              className="absolute bg-green-500 border-x-4 border-b-4 border-green-800"
              style={{
                left: pipe.x,
                top: 0,
                width: PIPE_WIDTH,
                height: pipe.topHeight,
                transition: 'none'
              }}
            >
              {/* Pipe Cap */}
              <div className="absolute bottom-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* Bottom Pipe */}
            <div 
              className="absolute bg-green-500 border-x-4 border-t-4 border-green-800"
              style={{
                left: pipe.x,
                top: pipe.topHeight + physicsConfigRef.current.gapSize,
                width: PIPE_WIDTH,
                height: GAME_HEIGHT - GROUND_HEIGHT - (pipe.topHeight + physicsConfigRef.current.gapSize),
                transition: 'none'
              }}
            >
               {/* Pipe Cap */}
               <div className="absolute top-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>
          </React.Fragment>
        ))}

        {/* Ground */}
        <div 
          className="absolute bottom-0 w-full bg-[#ded895] border-t-4 border-[#cbb968] z-20"
          style={{ height: GROUND_HEIGHT }}
        >
          {/* Moving ground pattern */}
           <div 
            className="w-full h-4 bg-[url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAQAAAAECAYAAACp8Z5+AAAAIklEQVQIW2NkQAKrVq36zwjjgzjIHFBMkCdYAL4YxAHLAAAYDBQz5/tq+AAAAABJRU5ErkJggg==')] opacity-30 animate-pulse"
           ></div>
        </div>

        {/* Bird */}
        <div 
          className="absolute z-30 flex items-center justify-center text-3xl"
          style={{
            left: (GAME_WIDTH / 2) - (BIRD_SIZE / 2),
            top: birdRef.current.y - (BIRD_SIZE / 2),
            width: BIRD_SIZE,
            height: BIRD_SIZE,
            transform: `rotate(${birdRef.current.rotation}deg) scale(${birdRef.current.scale})`,
            transition: 'transform 0.1s linear' // Slight smoothing for rotation
          }}
        >
          <span className="filter drop-shadow-md">🐥</span>
        </div>

        {/* HUD */}
        <div className="absolute top-4 w-full flex justify-between px-6 pointer-events-none z-40">
           <div className="flex flex-col">
             <span className="text-4xl font-bold pixel-text text-white drop-shadow-md">{score}</span>
             <span className="text-sm text-slate-100 font-bold bg-black/30 px-2 rounded">LVL {level}</span>
           </div>

           <div className="flex gap-1">
             {activePerks.map((p, i) => (
               <div key={i} className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center text-lg border border-white/40" title={p.name}>
                 {p.icon}
               </div>
             ))}
           </div>
        </div>

        {/* Start Screen */}
        {gameState === GameState.START && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-50">
            <h1 className="text-6xl text-yellow-400 font-bold pixel-text mb-4 animate-bounce">FLAPPY ROGUE</h1>
            <div className="bg-white/90 text-slate-900 p-6 rounded-lg border-4 border-slate-900 shadow-[8px_8px_0_0_rgba(0,0,0,0.5)]">
               <p className="text-xl text-center mb-4 font-bold">TAP or SPACE to JUMP</p>
               <p className="text-sm text-center text-slate-600">Survive pipes. Level up. Pick perks.</p>
            </div>
          </div>
        )}

        {/* Level Up Screen */}
        {gameState === GameState.LEVEL_UP && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 z-50 p-4">
            <h2 className="text-4xl text-yellow-300 font-bold pixel-text mb-6">LEVEL UP!</h2>
            <div className="grid gap-4 w-full max-w-sm">
              {offeredPerks.map(perk => (
                <button
                  key={perk.id}
                  onClick={() => selectPerk(perk)}
                  className={`
                    flex items-center gap-4 p-4 rounded border-b-4 active:border-b-0 active:translate-y-1 transition-all
                    ${perk.rarity === 'common' ? 'bg-slate-200 border-slate-400 text-slate-900' : ''}
                    ${perk.rarity === 'rare' ? 'bg-blue-100 border-blue-400 text-blue-900' : ''}
                    ${perk.rarity === 'legendary' ? 'bg-amber-100 border-amber-400 text-amber-900' : ''}
                  `}
                >
                  <span className="text-3xl">{perk.icon}</span>
                  <div className="text-left">
                    <div className="font-bold uppercase flex items-center gap-2">
                      {perk.name}
                      <span className="text-[10px] px-1 bg-black/10 rounded">{perk.rarity}</span>
                    </div>
                    <div className="text-sm opacity-80 leading-tight">{perk.description}</div>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Game Over Screen */}
        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-900/80 z-50">
            <h2 className="text-5xl text-white font-bold pixel-text mb-2">GAME OVER</h2>

            <div className="bg-white text-slate-900 p-6 rounded-lg w-64 text-center border-4 border-slate-900 mb-6 shadow-[8px_8px_0_0_rgba(0,0,0,0.5)]">
              <div className="flex justify-between mb-2">
                <span className="text-slate-500 uppercase font-bold text-sm">Score</span>
                <span className="text-2xl font-bold">{score}</span>
              </div>
              <div className="flex justify-between border-t border-slate-300 pt-2">
                <span className="text-slate-500 uppercase font-bold text-sm">Best</span>
                <span className="text-2xl font-bold text-orange-600">{Math.max(score, highScore)}</span>
              </div>
            </div>

            <button 
              onClick={resetGame}
              className="bg-green-500 hover:bg-green-600 text-white text-2xl font-bold py-3 px-8 rounded shadow-[0_4px_0_0_rgba(21,128,61,1)] active:shadow-none active:translate-y-1 transition-all"
            >
              RETRY
            </button>
          </div>
        )}

      </div>

      <div className="mt-4 text-slate-500 text-sm">
        Desktop: SPACE to Jump | Mobile: TAP
      </div>
    </div>
  );
};

export default GameEngine;

