import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GameState, PhysicsConfig, PipeEntity, BirdState, Perk } from '../types';
import { 
  GAME_WIDTH, 
  GAME_HEIGHT, 
  INITIAL_PHYSICS, 
  BIRD_SIZE, 
  PIPE_WIDTH, 
  GROUND_HEIGHT, 
  AVAILABLE_PERKS,
  LEVEL_UP_XP_REQ,
  PIPE_POOL_SIZE,
  ORB_SIZE
} from '../constants';

const GameEngine: React.FC = () => {
  // --- React State (UI Only) ---
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [score, setScore] = useState(0);
  const [xp, setXp] = useState(0);
  const [level, setLevel] = useState(1);
  const [highScore, setHighScore] = useState(0);
  const [activePerks, setActivePerks] = useState<Perk[]>([]);
  const [offeredPerks, setOfferedPerks] = useState<Perk[]>([]);
  const [currentHp, setCurrentHp] = useState(1);
  const [maxHp, setMaxHp] = useState(1);

  // --- Refs (Physics & Direct DOM Access) ---
  const birdRef = useRef<BirdState>({ 
    y: GAME_HEIGHT / 2, 
    velocity: 0, 
    rotation: 0, 
    scale: 1, 
    hp: 1, 
    maxHp: 1, 
    isInvulnerable: false, 
    invulnTimer: 0 
  });

  const physicsConfigRef = useRef<PhysicsConfig>({ ...INITIAL_PHYSICS });
  const pipesRef = useRef<PipeEntity[]>([]);
  const frameRef = useRef<number>(0);
  const lastTimeRef = useRef<number>(0);
  const activePerksRef = useRef<Set<string>>(new Set()); // Faster lookups

  // DOM Refs (For direct manipulation without React render)
  const birdDomRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pipePoolRefs = useRef<(HTMLDivElement | null)[]>([]); // Array of refs to pipe elements

  // --- Engine Logic ---

  const resetGame = () => {
    birdRef.current = { 
      y: GAME_HEIGHT / 2, 
      velocity: 0, 
      rotation: 0, 
      scale: 1, 
      hp: 1, 
      maxHp: 1, 
      isInvulnerable: false, 
      invulnTimer: 0 
    };
    pipesRef.current = [];
    physicsConfigRef.current = { ...INITIAL_PHYSICS };
    activePerksRef.current.clear();

    // Reset Pool Styles
    pipePoolRefs.current.forEach(el => {
      if (el) el.style.transform = `translate3d(-200px, 0, 0)`; // Move offscreen
    });

    setScore(0);
    setXp(0);
    setLevel(1);
    setActivePerks([]);
    setCurrentHp(1);
    setMaxHp(1);
    setGameState(GameState.START);
  };

  const spawnPipe = (offset: number) => {
    // Find an available pool index that isn't currently used by an active pipe
    const usedIndices = new Set(pipesRef.current.map(p => p.poolIndex));
    let poolIndex = -1;
    for (let i = 0; i < PIPE_POOL_SIZE; i++) {
      if (!usedIndices.has(i)) {
        poolIndex = i;
        break;
      }
    }

    if (poolIndex === -1) return; // Should not happen with correct pool size vs spacing

    const config = physicsConfigRef.current;
    const minPipeHeight = 50;
    const maxPipeHeight = GAME_HEIGHT - GROUND_HEIGHT - config.gapSize - minPipeHeight;
    const randomHeight = Math.floor(Math.random() * (maxPipeHeight - minPipeHeight + 1)) + minPipeHeight;

    // 30% chance for an Orb
    const hasOrb = Math.random() < 0.3;
    const orbY = randomHeight + (config.gapSize / 2) - (ORB_SIZE / 2);

    pipesRef.current.push({
      id: Date.now() + Math.random(),
      x: offset,
      topHeight: randomHeight,
      passed: false,
      poolIndex,
      hasOrb,
      orbY,
      orbCollected: false
    });
  };

  const jump = useCallback((e?: React.SyntheticEvent | Event) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (gameState === GameState.PLAYING) {
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
    } else if (gameState === GameState.START) {
      setGameState(GameState.PLAYING);
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
      lastTimeRef.current = performance.now();
    }
  }, [gameState]);

  const takeDamage = () => {
    const bird = birdRef.current;
    if (bird.isInvulnerable) return;

    bird.hp -= 1;
    setCurrentHp(bird.hp);

    if (bird.hp <= 0) {
      setGameState(GameState.GAME_OVER);
      setHighScore(prev => Math.max(prev, score));
    } else {
      // Invulnerability frames
      bird.isInvulnerable = true;
      bird.invulnTimer = 60; // ~1 second at 60fps

      // Visual feedback
      if (birdDomRef.current) {
        birdDomRef.current.style.filter = 'brightness(500%) sepia(100%) hue-rotate(-50deg) saturate(600%)';
        setTimeout(() => {
          if (birdDomRef.current) birdDomRef.current.style.filter = 'none';
        }, 100);
      }
    }
  };

  const gainXp = (amount: number) => {
    setXp(prev => {
      const nextXp = prev + amount;
      if (nextXp >= LEVEL_UP_XP_REQ) {
        // Schedule level up logic outside render loop to avoid clashes
        requestAnimationFrame(() => {
           setGameState(GameState.LEVEL_UP);
           // Generate Perks
           const available = AVAILABLE_PERKS.filter(p => {
             // Filter out unique perks if already have them? (For now allow stacking some)
             if (p.id === 'tiny_bird' && activePerksRef.current.has('tiny_bird')) return false;
             return true;
           });
           const shuffled = [...available].sort(() => 0.5 - Math.random());
           setOfferedPerks(shuffled.slice(0, 3));
        });
        return 0; // Reset XP or keep overflow? Let's reset for simple levels
      }
      return nextXp;
    });
  };

  const selectPerk = (perk: Perk) => {
    setActivePerks(prev => [...prev, perk]);
    activePerksRef.current.add(perk.id);

    // Apply Physics
    if (perk.apply) {
      physicsConfigRef.current = perk.apply(physicsConfigRef.current);
    }

    // Apply Stats
    if (perk.id === 'vitality') {
      birdRef.current.maxHp += 1;
      birdRef.current.hp += 1;
      setMaxHp(prev => prev + 1);
      setCurrentHp(prev => prev + 1);
    }
    if (perk.id === 'tiny_bird') {
      birdRef.current.scale = 0.7;
    }

    setLevel(l => l + 1);
    setGameState(GameState.PLAYING);
    lastTimeRef.current = performance.now();
  };

  // --- Main Game Loop (Optimized) ---
  const update = useCallback((time: number) => {
    // Delta time calculation for smooth physics regardless of framerate
    const delta = time - lastTimeRef.current;
    lastTimeRef.current = time;

    // Cap dt to prevent huge jumps if tab was inactive
    const dt = Math.min(delta / 16.67, 2.0); 

    if (gameState === GameState.START) {
      // Hover animation
      const hoverY = (GAME_HEIGHT / 2) + Math.sin(time / 300) * 12;
      if (birdDomRef.current) {
        birdDomRef.current.style.transform = `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${hoverY}px, 0) rotate(0deg)`;
      }
      frameRef.current = requestAnimationFrame(update);
      return;
    }

    if (gameState !== GameState.PLAYING) {
      return; // Stop loop if paused/gameover
    }

    const config = physicsConfigRef.current;
    const bird = birdRef.current;
    const pipes = pipesRef.current;

    // --- Physics ---

    // Bird Gravity
    bird.velocity += config.gravity * dt;
    bird.y += bird.velocity * dt;

    // Floor Collision
    if (bird.y >= GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2)) {
      bird.y = GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2);
      takeDamage();
      if (bird.hp > 0) bird.velocity = config.jumpStrength * 1.2; // Bounce if alive
    }
    // Ceiling
    if (bird.y < 0) {
      bird.y = 0;
      bird.velocity = 0;
    }

    // Invulnerability Timer
    if (bird.isInvulnerable) {
      bird.invulnTimer -= dt;
      if (bird.invulnTimer <= 0) bird.isInvulnerable = false;
    }

    // Rotation
    bird.rotation = Math.min(Math.max(bird.velocity * 3.5, -25), 90);

    // --- Pipe Management ---

    // Spawn Logic
    const lastPipe = pipes[pipes.length - 1];
    const spawnDist = config.spawnRate;
    if (!lastPipe || (GAME_WIDTH - lastPipe.x) > spawnDist) {
      spawnPipe(GAME_WIDTH);
    }

    // Move & Collide
    for (let i = pipes.length - 1; i >= 0; i--) {
      const p = pipes[i];
      p.x -= config.pipeSpeed * dt;

      // Magnet Logic
      if (p.hasOrb && !p.orbCollected && activePerksRef.current.has('magnet')) {
         const dx = (GAME_WIDTH / 2) - (p.x + PIPE_WIDTH/2);
         const dy = bird.y - p.orbY;
         const dist = Math.sqrt(dx*dx + dy*dy);
         if (dist < 200) {
            p.orbY += dy * 0.1 * dt; // Move towards bird Y
            // Visual X movement is tricky since pipe controls X, but we can simulate it strictly visually or just Y
         }
      }

      // Remove off-screen
      if (p.x + PIPE_WIDTH < -50) {
        // Move DOM element offscreen to hide it
        const domEl = pipePoolRefs.current[p.poolIndex];
        if (domEl) domEl.style.transform = `translate3d(-200px, 0, 0)`;

        pipes.splice(i, 1);
        continue;
      }

      // Collision Boxes
      const birdRadius = (BIRD_SIZE * bird.scale) / 2;
      const birdX = GAME_WIDTH / 2;

      // Rect-Circle Collision (Simplified to Box-Box for performance)
      const birdLeft = birdX - birdRadius + 4;
      const birdRight = birdX + birdRadius - 4;
      const birdTop = bird.y - birdRadius + 4;
      const birdBottom = bird.y + birdRadius - 4;

      const pipeLeft = p.x;
      const pipeRight = p.x + PIPE_WIDTH;

      // Pipe Collision
      if (birdRight > pipeLeft && birdLeft < pipeRight) {
        const hitTop = birdTop < p.topHeight;
        const hitBottom = birdBottom > (p.topHeight + config.gapSize);

        if (hitTop || hitBottom) {
           takeDamage();
        }
      }

      // Orb Collision
      if (p.hasOrb && !p.orbCollected) {
         const orbX = p.x + (PIPE_WIDTH/2);
         const orbY = p.orbY;
         const dx = birdX - orbX;
         const dy = bird.y - orbY;
         if (Math.sqrt(dx*dx + dy*dy) < (BIRD_SIZE + ORB_SIZE)/2) {
            p.orbCollected = true;
            gainXp(1); // Bonus XP
         }
      }

      // Passing Score
      if (!p.passed && p.x + PIPE_WIDTH < birdLeft) {
        p.passed = true;
        setScore(s => s + 1);
        gainXp(1);
      }
    }

    // --- Render Updates (Direct DOM) ---

    // Bird
    if (birdDomRef.current) {
      birdDomRef.current.style.transform = 
        `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(bird.y - (BIRD_SIZE/2))}px, 0) ` + 
        `rotate(${Math.round(bird.rotation)}deg) scale(${bird.scale})`;

      // Blink effect
      birdDomRef.current.style.opacity = bird.isInvulnerable && Math.floor(time / 100) % 2 === 0 ? '0.5' : '1';
    }

    // Pipes
    pipes.forEach(p => {
      const el = pipePoolRefs.current[p.poolIndex];
      if (el) {
        // We use CSS variables or child searching to update height efficiently? 
        // Better: The pool elements are generic, we set their specific styles here.
        // To avoid finding children every frame, let's assume specific structure or use css vars.
        // Actually, React rendered the pool initially. We can just move the CONTAINER X/Y.
        // But height changes per pipe.
        // Fastest way: Update style attributes.

        el.style.transform = `translate3d(${Math.round(p.x)}px, 0, 0)`;

        // Only need to set height if it changed (new pipe assignment)
        // We can check a data attribute to see if we need to redraw dimensions
        if (el.dataset.lastId !== String(p.id)) {
           el.dataset.lastId = String(p.id);

           // Update Top Pipe Height
           const topPipe = el.firstElementChild as HTMLElement;
           if (topPipe) topPipe.style.height = `${p.topHeight}px`;

           // Update Bottom Pipe Position/Height
           const bottomPipe = el.lastElementChild?.previousElementSibling as HTMLElement; // Assuming structure
           if (bottomPipe) {
             bottomPipe.style.top = `${p.topHeight + config.gapSize}px`;
             bottomPipe.style.height = `${GAME_HEIGHT - GROUND_HEIGHT - (p.topHeight + config.gapSize)}px`;
           }

           // Update Orb
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) {
              orb.style.display = p.hasOrb ? 'block' : 'none';
              orb.style.top = `${p.orbY}px`;
           }
        }

        // Update Orb visibility if collected
        if (p.orbCollected) {
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.display = 'none';
        } else if (p.hasOrb && activePerksRef.current.has('magnet')) {
           // Update dynamic orb Y if magnet is active
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.top = `${p.orbY}px`;
        }
      }
    });

    frameRef.current = requestAnimationFrame(update);
  }, [gameState]); // Dependencies minimized

  // Start/Stop Loop
  useEffect(() => {
    if (gameState === GameState.PLAYING || gameState === GameState.START) {
      lastTimeRef.current = performance.now();
      frameRef.current = requestAnimationFrame(update);
    }
    return () => cancelAnimationFrame(frameRef.current);
  }, [gameState, update]);

  // Input Listeners
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.code === 'Space') jump(e);
    };
    // Passive: false is crucial for touch to prevent scrolling and ensure immediate response
    window.addEventListener('keydown', handler);
    window.addEventListener('touchstart', jump as any, { passive: false });
    window.addEventListener('mousedown', jump as any);

    return () => {
      window.removeEventListener('keydown', handler);
      window.removeEventListener('touchstart', jump as any);
      window.removeEventListener('mousedown', jump as any);
    };
  }, [jump]);

  // Initial Pool Creation
  // We render a static pool of pipes that are recycled.
  const pipePool = useMemo(() => {
    return Array.from({ length: PIPE_POOL_SIZE }).map((_, i) => i);
  }, []);

  return (
    <div className="w-screen h-screen overflow-hidden bg-slate-950 font-mono select-none">

      {/* Game Stage */}
      <div 
        ref={containerRef}
        className="relative w-full h-full"
        style={{ width: GAME_WIDTH, height: GAME_HEIGHT, background: 'linear-gradient(to bottom, #4facfe 0%, #00f2fe 100%)' }}
      >
        {/* Background Elements (Static) */}
        <div className="absolute top-[10%] left-[5%] opacity-50 text-white text-6xl pointer-events-none">☁️</div>
        <div className="absolute top-[20%] left-[40%] opacity-40 text-white text-5xl pointer-events-none">☁️</div>
        <div className="absolute top-[5%] left-[70%] opacity-60 text-white text-4xl pointer-events-none">☁️</div>
        <div className="absolute top-[15%] left-[90%] opacity-30 text-white text-5xl pointer-events-none">☁️</div>

        {/* --- Render Pipe Pool --- */}
        {pipePool.map((i) => (
          <div
            key={i}
            ref={el => pipePoolRefs.current[i] = el}
            className="absolute top-0 left-0 w-full h-full pointer-events-none will-change-transform"
            style={{ transform: 'translate3d(-200px, 0, 0)' }} // Start hidden
          >
            {/* Top Pipe */}
            <div className="absolute left-0 top-0 bg-green-500 border-x-4 border-b-4 border-green-800 transition-none w-[52px]">
               <div className="absolute bottom-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* Bottom Pipe */}
            <div className="absolute left-0 bg-green-500 border-x-4 border-t-4 border-green-800 transition-none w-[52px]">
               <div className="absolute top-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* XP Orb */}
            <div className="orb absolute left-[14px] w-6 h-6 rounded-full bg-yellow-300 border-2 border-yellow-500 shadow-[0_0_10px_rgba(253,224,71,0.8)] animate-pulse hidden z-10"></div>
          </div>
        ))}

        {/* Ground */}
        <div 
          className="absolute bottom-0 w-full bg-[#ded895] border-t-4 border-[#cbb968] z-20"
          style={{ height: GROUND_HEIGHT }}
        >
           <div className="w-full h-4 bg-[url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAQAAAAECAYAAACp8Z5+AAAAIklEQVQIW2NkQAKrVq36zwjjgzjIHFBMkCdYAL4YxAHLAAAYDBQz5/tq+AAAAABJRU5ErkJggg==')] opacity-30 animate-pulse"></div>
        </div>

        {/* Bird (Direct DOM) */}
        <div 
          ref={birdDomRef}
          className="absolute top-0 left-0 z-30 flex items-center justify-center will-change-transform pointer-events-none"
          style={{
            width: BIRD_SIZE,
            height: BIRD_SIZE,
            transform: `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${(GAME_HEIGHT/2)}px, 0)`
          }}
        >
          <span className="text-3xl filter drop-shadow-md">🐥</span>
        </div>

        {/* UI Layer (React) */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-40 p-4">
           {/* HUD */}
           <div className="flex justify-between items-start">
              <div>
                 <div className="flex items-baseline gap-2">
                    <span className="text-5xl font-bold pixel-text text-white drop-shadow-md leading-none">{score}</span>
                    <span className="text-sm bg-black/40 px-2 py-0.5 rounded text-white font-bold">LVL {level}</span>
                 </div>
                 {/* Hearts */}
                 <div className="flex mt-1">
                    {Array.from({length: maxHp}).map((_, i) => (
                       <span key={i} className={`text-xl ${i < currentHp ? 'grayscale-0' : 'grayscale opacity-30'}`}>❤️</span>
                    ))}
                 </div>
              </div>

              {/* Perks List */}
              <div className="flex flex-col gap-1 items-end">
                 {activePerks.map((p, i) => (
                    <div key={i} className="bg-black/40 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 backdrop-blur-sm border border-white/20">
                       <span>{p.icon}</span>
                       <span className="max-w-[80px] truncate hidden sm:inline">{p.name}</span>
                    </div>
                 ))}
              </div>
           </div>

           {/* XP Bar */}
           <div className="absolute bottom-[50px] left-4 right-4 h-2 bg-black/50 rounded-full overflow-hidden border border-white/20 max-w-3xl mx-auto">
              <div 
                 className="h-full bg-yellow-400 transition-all duration-300"
                 style={{ width: `${(xp / LEVEL_UP_XP_REQ) * 100}%` }}
              ></div>
           </div>
        </div>

        {/* Overlays */}
        {gameState === GameState.START && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-50 backdrop-blur-[2px]">
            <h1 className="text-8xl text-yellow-400 font-bold pixel-text mb-4 animate-bounce drop-shadow-[6px_6px_0_#000]">FLAPPY ROGUE</h1>
            <div className="bg-slate-900 text-white p-8 rounded-xl border-4 border-slate-700 shadow-xl text-center min-w-[300px]">
               <p className="text-2xl mb-6 font-bold animate-pulse text-yellow-200">PRESS SPACE TO START</p>
               <div className="text-lg text-slate-400 space-y-2">
                  <p>❤️ Avoid Pipes & Ground</p>
                  <p>🟡 Collect Orbs for XP</p>
                  <p>⚡ Level Up & Get Broken Perks</p>
               </div>
            </div>
          </div>
        )}

        {gameState === GameState.LEVEL_UP && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-50 p-4">
             <h2 className="text-6xl text-yellow-300 font-bold pixel-text mb-8 drop-shadow-md">LEVEL {level + 1}</h2>
             <p className="text-white mb-6 text-xl">Choose a Perk:</p>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl pointer-events-auto px-6">
               {offeredPerks.map(perk => (
                 <button
                   key={perk.id}
                   onClick={() => selectPerk(perk)}
                   className={`
                     relative flex flex-col items-center justify-center text-center gap-4 p-8 rounded-xl border-b-8 active:border-b-0 active:translate-y-2 transition-all group overflow-hidden h-64
                     ${perk.rarity === 'common' ? 'bg-slate-200 border-slate-400 text-slate-900' : ''}
                     ${perk.rarity === 'rare' ? 'bg-blue-100 border-blue-400 text-blue-900' : ''}
                     ${perk.rarity === 'legendary' ? 'bg-amber-100 border-amber-400 text-amber-900' : ''}
                   `}
                 >
                   <div className="absolute right-0 top-0 opacity-10 text-9xl rotate-12 -mr-8 -mt-4 group-hover:scale-110 transition-transform">{perk.icon}</div>
                   <span className="text-6xl z-10 drop-shadow-sm mb-2">{perk.icon}</span>
                   <div className="z-10 w-full">
                     <div className="font-bold uppercase flex items-center justify-center gap-2 text-xl mb-2">
                       {perk.name}
                       <span className="text-xs px-2 py-1 bg-black/10 rounded-full font-extrabold tracking-wide uppercase">{perk.rarity}</span>
                     </div>
                     <div className="text-base opacity-90 leading-tight font-medium">{perk.description}</div>
                   </div>
                 </button>
               ))}
             </div>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-950/90 z-50 backdrop-blur-sm pointer-events-auto">
            <h2 className="text-8xl text-white font-bold pixel-text mb-4 drop-shadow-[6px_6px_0_#000]">GAME OVER</h2>

            <div className="bg-slate-100 text-slate-900 p-8 rounded-xl w-80 text-center border-8 border-slate-900 mb-8 shadow-2xl transform scale-125">
              <div className="flex justify-between mb-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Score</span>
                <span className="text-4xl font-bold">{score}</span>
              </div>
              <div className="flex justify-between border-t-4 border-slate-300 pt-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Best</span>
                <span className="text-4xl font-bold text-orange-600">{Math.max(score, highScore)}</span>
              </div>
              <div className="mt-6 text-sm text-slate-400 font-mono">
                 Lvl {level} • {activePerks.length} Perks
              </div>
            </div>

            <button 
              onClick={resetGame}
              className="bg-green-500 hover:bg-green-600 text-white text-3xl font-bold py-6 px-16 rounded-2xl shadow-[0_8px_0_0_rgba(21,128,61,1)] active:shadow-none active:translate-y-2 transition-all mt-4"
            >
              RETRY
            </button>
          </div>
        )}

      </div>
    </div>
  );
};

export default GameEngine;

export enum GameState {
  START = 'START',
  PLAYING = 'PLAYING',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  RESUMING = 'RESUMING'
}

export interface PhysicsConfig {
  gravity: number;
  jumpStrength: number;
  pipeSpeed: number;
  gapSize: number;
  spawnRate: number; // Distance between pipes
}

export interface Perk {
  id: string;
  name: string;
  description: string;
  rarity: 'common' | 'rare' | 'legendary';
  icon: string;
  // Some perks modify physics, others are handled by ID logic (like HP)
  apply?: (config: PhysicsConfig) => PhysicsConfig; 
}

// Logical representation of a pipe for the physics engine
export interface PipeEntity {
  id: number;
  x: number;
  topHeight: number;
  passed: boolean;
  poolIndex: number; // Which DOM element represents this pipe

  // Roguelike elements
  hasOrb: boolean;
  orbY: number;
  orbCollected: boolean;
}

export interface BirdState {
  y: number;
  velocity: number;
  rotation: number;
  scale: number;

  // Roguelike stats
  hp: number;
  maxHp: number;
  isInvulnerable: boolean;
  invulnTimer: number;
}

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GameState, PhysicsConfig, PipeEntity, BirdState, Perk } from '../types';
import { 
  GAME_WIDTH, 
  GAME_HEIGHT, 
  INITIAL_PHYSICS, 
  BIRD_SIZE, 
  PIPE_WIDTH, 
  GROUND_HEIGHT, 
  AVAILABLE_PERKS,
  LEVEL_UP_XP_REQ,
  PIPE_POOL_SIZE,
  ORB_SIZE
} from '../constants';

const GameEngine: React.FC = () => {
  // --- React State (UI Only) ---
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [score, setScore] = useState(0);
  const [xp, setXp] = useState(0);
  const [level, setLevel] = useState(1);
  const [highScore, setHighScore] = useState(0);
  const [activePerks, setActivePerks] = useState<Perk[]>([]);
  const [offeredPerks, setOfferedPerks] = useState<Perk[]>([]);
  const [currentHp, setCurrentHp] = useState(1);
  const [maxHp, setMaxHp] = useState(1);
  const [countdown, setCountdown] = useState(3);

  // --- Refs (Physics & Direct DOM Access) ---
  const birdRef = useRef<BirdState>({ 
    y: GAME_HEIGHT / 2, 
    velocity: 0, 
    rotation: 0, 
    scale: 1, 
    hp: 1, 
    maxHp: 1, 
    isInvulnerable: false, 
    invulnTimer: 0 
  });

  const physicsConfigRef = useRef<PhysicsConfig>({ ...INITIAL_PHYSICS });
  const pipesRef = useRef<PipeEntity[]>([]);
  const frameRef = useRef<number>(0);
  const lastTimeRef = useRef<number>(0);
  const activePerksRef = useRef<Set<string>>(new Set()); // Faster lookups

  // DOM Refs (For direct manipulation without React render)
  const birdDomRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pipePoolRefs = useRef<(HTMLDivElement | null)[]>([]); // Array of refs to pipe elements

  // --- Engine Logic ---

  const resetGame = () => {
    birdRef.current = { 
      y: GAME_HEIGHT / 2, 
      velocity: 0, 
      rotation: 0, 
      scale: 1, 
      hp: 1, 
      maxHp: 1, 
      isInvulnerable: false, 
      invulnTimer: 0 
    };
    pipesRef.current = [];
    physicsConfigRef.current = { ...INITIAL_PHYSICS };
    activePerksRef.current.clear();

    // Reset Pool Styles
    pipePoolRefs.current.forEach(el => {
      if (el) el.style.transform = `translate3d(-200px, 0, 0)`; // Move offscreen
    });

    setScore(0);
    setXp(0);
    setLevel(1);
    setActivePerks([]);
    setCurrentHp(1);
    setMaxHp(1);
    setGameState(GameState.START);
  };

  const spawnPipe = (offset: number) => {
    // Find an available pool index that isn't currently used by an active pipe
    const usedIndices = new Set(pipesRef.current.map(p => p.poolIndex));
    let poolIndex = -1;
    for (let i = 0; i < PIPE_POOL_SIZE; i++) {
      if (!usedIndices.has(i)) {
        poolIndex = i;
        break;
      }
    }

    if (poolIndex === -1) return; // Should not happen with correct pool size vs spacing

    const config = physicsConfigRef.current;
    const minPipeHeight = 50;
    const maxPipeHeight = GAME_HEIGHT - GROUND_HEIGHT - config.gapSize - minPipeHeight;
    const randomHeight = Math.floor(Math.random() * (maxPipeHeight - minPipeHeight + 1)) + minPipeHeight;

    // 30% chance for an Orb
    const hasOrb = Math.random() < 0.3;
    const orbY = randomHeight + (config.gapSize / 2) - (ORB_SIZE / 2);

    pipesRef.current.push({
      id: Date.now() + Math.random(),
      x: offset,
      topHeight: randomHeight,
      passed: false,
      poolIndex,
      hasOrb,
      orbY,
      orbCollected: false
    });
  };

  const jump = useCallback((e?: React.SyntheticEvent | Event) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (gameState === GameState.PLAYING) {
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
    } else if (gameState === GameState.START) {
      setGameState(GameState.PLAYING);
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
      lastTimeRef.current = performance.now();
    }
  }, [gameState]);

  const takeDamage = () => {
    const bird = birdRef.current;
    if (bird.isInvulnerable) return;

    bird.hp -= 1;
    setCurrentHp(bird.hp);

    if (bird.hp <= 0) {
      setGameState(GameState.GAME_OVER);
      setHighScore(prev => Math.max(prev, score));
    } else {
      // Invulnerability frames
      bird.isInvulnerable = true;
      bird.invulnTimer = 60; // ~1 second at 60fps

      // Visual feedback
      if (birdDomRef.current) {
        birdDomRef.current.style.filter = 'brightness(500%) sepia(100%) hue-rotate(-50deg) saturate(600%)';
        setTimeout(() => {
          if (birdDomRef.current) birdDomRef.current.style.filter = 'none';
        }, 100);
      }
    }
  };

  const gainXp = (amount: number) => {
    setXp(prev => {
      const nextXp = prev + amount;
      if (nextXp >= LEVEL_UP_XP_REQ) {
        // Schedule level up logic outside render loop to avoid clashes
        requestAnimationFrame(() => {
           setGameState(GameState.LEVEL_UP);
           // Generate Perks
           const available = AVAILABLE_PERKS.filter(p => {
             // Filter out unique perks if already have them? (For now allow stacking some)
             if (p.id === 'tiny_bird' && activePerksRef.current.has('tiny_bird')) return false;
             return true;
           });
           const shuffled = [...available].sort(() => 0.5 - Math.random());
           setOfferedPerks(shuffled.slice(0, 3));
        });
        return 0; // Reset XP or keep overflow? Let's reset for simple levels
      }
      return nextXp;
    });
  };

  const selectPerk = (perk: Perk) => {
    setActivePerks(prev => [...prev, perk]);
    activePerksRef.current.add(perk.id);

    // Apply Physics
    if (perk.apply) {
      physicsConfigRef.current = perk.apply(physicsConfigRef.current);
    }

    // Apply Stats
    if (perk.id === 'vitality') {
      birdRef.current.maxHp += 1;
      birdRef.current.hp += 1;
      setMaxHp(prev => prev + 1);
      setCurrentHp(prev => prev + 1);
    }
    if (perk.id === 'tiny_bird') {
      birdRef.current.scale = 0.7;
    }

    setLevel(l => l + 1);

    // Instead of PLAYING immediately, go to RESUMING
    setGameState(GameState.RESUMING);
  };

  // Countdown Logic
  useEffect(() => {
    if (gameState === GameState.RESUMING) {
      setCountdown(3);
      const timer = setInterval(() => {
        setCountdown(prev => {
          if (prev <= 1) {
            clearInterval(timer);
            setGameState(GameState.PLAYING);
            lastTimeRef.current = performance.now(); // Reset time to prevent big physics jump
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [gameState]);

  // --- Main Game Loop (Optimized) ---
  const update = useCallback((time: number) => {
    // Delta time calculation for smooth physics regardless of framerate
    const delta = time - lastTimeRef.current;
    lastTimeRef.current = time;

    // Cap dt to prevent huge jumps if tab was inactive
    const dt = Math.min(delta / 16.67, 2.0); 

    if (gameState === GameState.START) {
      // Hover animation
      const hoverY = (GAME_HEIGHT / 2) + Math.sin(time / 300) * 12;
      if (birdDomRef.current) {
        birdDomRef.current.style.transform = `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${hoverY}px, 0) rotate(0deg)`;
      }
      frameRef.current = requestAnimationFrame(update);
      return;
    }

    // Handle Resuming State - Render Static
    if (gameState === GameState.RESUMING) {
       // Keep rendering the bird static so it doesn't disappear
       if (birdDomRef.current) {
          birdDomRef.current.style.transform = 
            `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(birdRef.current.y - (BIRD_SIZE/2))}px, 0) ` + 
            `rotate(${Math.round(birdRef.current.rotation)}deg) scale(${birdRef.current.scale})`;
       }
       frameRef.current = requestAnimationFrame(update);
       return;
    }

    if (gameState !== GameState.PLAYING) {
      return; // Stop loop if paused/gameover
    }

    const config = physicsConfigRef.current;
    const bird = birdRef.current;
    const pipes = pipesRef.current;

    // --- Physics ---

    // Bird Gravity
    bird.velocity += config.gravity * dt;
    bird.y += bird.velocity * dt;

    // Floor Collision
    if (bird.y >= GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2)) {
      bird.y = GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2);
      takeDamage();
      if (bird.hp > 0) bird.velocity = config.jumpStrength * 1.2; // Bounce if alive
    }
    // Ceiling
    if (bird.y < 0) {
      bird.y = 0;
      bird.velocity = 0;
    }

    // Invulnerability Timer
    if (bird.isInvulnerable) {
      bird.invulnTimer -= dt;
      if (bird.invulnTimer <= 0) bird.isInvulnerable = false;
    }

    // Rotation
    bird.rotation = Math.min(Math.max(bird.velocity * 3.5, -25), 90);

    // --- Pipe Management ---

    // Spawn Logic
    const lastPipe = pipes[pipes.length - 1];
    const spawnDist = config.spawnRate;
    if (!lastPipe || (GAME_WIDTH - lastPipe.x) > spawnDist) {
      spawnPipe(GAME_WIDTH);
    }

    // Move & Collide
    for (let i = pipes.length - 1; i >= 0; i--) {
      const p = pipes[i];
      p.x -= config.pipeSpeed * dt;

      // Magnet Logic
      if (p.hasOrb && !p.orbCollected && activePerksRef.current.has('magnet')) {
         const dx = (GAME_WIDTH / 2) - (p.x + PIPE_WIDTH/2);
         const dy = bird.y - p.orbY;
         const dist = Math.sqrt(dx*dx + dy*dy);
         if (dist < 200) {
            p.orbY += dy * 0.1 * dt; // Move towards bird Y
            // Visual X movement is tricky since pipe controls X, but we can simulate it strictly visually or just Y
         }
      }

      // Remove off-screen
      if (p.x + PIPE_WIDTH < -50) {
        // Move DOM element offscreen to hide it
        const domEl = pipePoolRefs.current[p.poolIndex];
        if (domEl) domEl.style.transform = `translate3d(-200px, 0, 0)`;

        pipes.splice(i, 1);
        continue;
      }

      // Collision Boxes
      const birdRadius = (BIRD_SIZE * bird.scale) / 2;
      const birdX = GAME_WIDTH / 2;

      // Rect-Circle Collision (Simplified to Box-Box for performance)
      const birdLeft = birdX - birdRadius + 4;
      const birdRight = birdX + birdRadius - 4;
      const birdTop = bird.y - birdRadius + 4;
      const birdBottom = bird.y + birdRadius - 4;

      const pipeLeft = p.x;
      const pipeRight = p.x + PIPE_WIDTH;

      // Pipe Collision
      if (birdRight > pipeLeft && birdLeft < pipeRight) {
        const hitTop = birdTop < p.topHeight;
        const hitBottom = birdBottom > (p.topHeight + config.gapSize);

        if (hitTop || hitBottom) {
           takeDamage();
        }
      }

      // Orb Collision
      if (p.hasOrb && !p.orbCollected) {
         const orbX = p.x + (PIPE_WIDTH/2);
         const orbY = p.orbY;
         const dx = birdX - orbX;
         const dy = bird.y - orbY;
         if (Math.sqrt(dx*dx + dy*dy) < (BIRD_SIZE + ORB_SIZE)/2) {
            p.orbCollected = true;
            gainXp(1); // Bonus XP
         }
      }

      // Passing Score
      if (!p.passed && p.x + PIPE_WIDTH < birdLeft) {
        p.passed = true;
        setScore(s => s + 1);
        gainXp(1);
      }
    }

    // --- Render Updates (Direct DOM) ---

    // Bird
    if (birdDomRef.current) {
      birdDomRef.current.style.transform = 
        `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(bird.y - (BIRD_SIZE/2))}px, 0) ` + 
        `rotate(${Math.round(bird.rotation)}deg) scale(${bird.scale})`;

      // Blink effect
      birdDomRef.current.style.opacity = bird.isInvulnerable && Math.floor(time / 100) % 2 === 0 ? '0.5' : '1';
    }

    // Pipes
    pipes.forEach(p => {
      const el = pipePoolRefs.current[p.poolIndex];
      if (el) {
        el.style.transform = `translate3d(${Math.round(p.x)}px, 0, 0)`;

        // Only need to set height if it changed (new pipe assignment)
        if (el.dataset.lastId !== String(p.id)) {
           el.dataset.lastId = String(p.id);

           // Update Top Pipe Height
           const topPipe = el.firstElementChild as HTMLElement;
           if (topPipe) topPipe.style.height = `${p.topHeight}px`;

           // Update Bottom Pipe Position/Height
           const bottomPipe = el.lastElementChild?.previousElementSibling as HTMLElement; // Assuming structure
           if (bottomPipe) {
             bottomPipe.style.top = `${p.topHeight + config.gapSize}px`;
             bottomPipe.style.height = `${GAME_HEIGHT - GROUND_HEIGHT - (p.topHeight + config.gapSize)}px`;
           }

           // Update Orb
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) {
              orb.style.display = p.hasOrb ? 'block' : 'none';
              orb.style.top = `${p.orbY}px`;
           }
        }

        // Update Orb visibility if collected
        if (p.orbCollected) {
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.display = 'none';
        } else if (p.hasOrb && activePerksRef.current.has('magnet')) {
           // Update dynamic orb Y if magnet is active
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.top = `${p.orbY}px`;
        }
      }
    });

    frameRef.current = requestAnimationFrame(update);
  }, [gameState]); // Dependencies minimized

  // Start/Stop Loop
  useEffect(() => {
    if (gameState === GameState.PLAYING || gameState === GameState.START || gameState === GameState.RESUMING) {
      lastTimeRef.current = performance.now();
      frameRef.current = requestAnimationFrame(update);
    }
    return () => cancelAnimationFrame(frameRef.current);
  }, [gameState, update]);

  // Input Listeners
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.code === 'Space') jump(e);
    };
    // Passive: false is crucial for touch to prevent scrolling and ensure immediate response
    window.addEventListener('keydown', handler);
    window.addEventListener('touchstart', jump as any, { passive: false });
    window.addEventListener('mousedown', jump as any);

    return () => {
      window.removeEventListener('keydown', handler);
      window.removeEventListener('touchstart', jump as any);
      window.removeEventListener('mousedown', jump as any);
    };
  }, [jump]);

  // Initial Pool Creation
  // We render a static pool of pipes that are recycled.
  const pipePool = useMemo(() => {
    return Array.from({ length: PIPE_POOL_SIZE }).map((_, i) => i);
  }, []);

  return (
    <div className="w-screen h-screen overflow-hidden bg-slate-950 font-mono select-none">

      {/* Game Stage */}
      <div 
        ref={containerRef}
        className="relative w-full h-full"
        style={{ width: GAME_WIDTH, height: GAME_HEIGHT, background: 'linear-gradient(to bottom, #4facfe 0%, #00f2fe 100%)' }}
      >
        {/* Background Elements (Static) */}
        <div className="absolute top-[10%] left-[5%] opacity-50 text-white text-6xl pointer-events-none">☁️</div>
        <div className="absolute top-[20%] left-[40%] opacity-40 text-white text-5xl pointer-events-none">☁️</div>
        <div className="absolute top-[5%] left-[70%] opacity-60 text-white text-4xl pointer-events-none">☁️</div>
        <div className="absolute top-[15%] left-[90%] opacity-30 text-white text-5xl pointer-events-none">☁️</div>

        {/* --- Render Pipe Pool --- */}
        {pipePool.map((i) => (
          <div
            key={i}
            ref={el => pipePoolRefs.current[i] = el}
            className="absolute top-0 left-0 w-full h-full pointer-events-none will-change-transform"
            style={{ transform: 'translate3d(-200px, 0, 0)' }} // Start hidden
          >
            {/* Top Pipe */}
            <div className="absolute left-0 top-0 bg-green-500 border-x-4 border-b-4 border-green-800 transition-none w-[52px]">
               <div className="absolute bottom-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* Bottom Pipe */}
            <div className="absolute left-0 bg-green-500 border-x-4 border-t-4 border-green-800 transition-none w-[52px]">
               <div className="absolute top-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* XP Orb */}
            <div className="orb absolute left-[14px] w-6 h-6 rounded-full bg-yellow-300 border-2 border-yellow-500 shadow-[0_0_10px_rgba(253,224,71,0.8)] animate-pulse hidden z-10"></div>
          </div>
        ))}

        {/* Ground */}
        <div 
          className="absolute bottom-0 w-full bg-[#ded895] border-t-4 border-[#cbb968] z-20"
          style={{ height: GROUND_HEIGHT }}
        >
           <div className="w-full h-4 bg-[url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAQAAAAECAYAAACp8Z5+AAAAIklEQVQIW2NkQAKrVq36zwjjgzjIHFBMkCdYAL4YxAHLAAAYDBQz5/tq+AAAAABJRU5ErkJggg==')] opacity-30 animate-pulse"></div>
        </div>

        {/* Bird (Direct DOM) */}
        <div 
          ref={birdDomRef}
          className="absolute top-0 left-0 z-30 flex items-center justify-center will-change-transform pointer-events-none"
          style={{
            width: BIRD_SIZE,
            height: BIRD_SIZE,
            transform: `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${(GAME_HEIGHT/2)}px, 0)`
          }}
        >
          <span className="text-3xl filter drop-shadow-md">🐥</span>
        </div>

        {/* UI Layer (React) */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-40 p-4">
           {/* HUD */}
           <div className="flex justify-between items-start">
              <div>
                 <div className="flex items-baseline gap-2">
                    <span className="text-5xl font-bold pixel-text text-white drop-shadow-md leading-none">{score}</span>
                    <span className="text-sm bg-black/40 px-2 py-0.5 rounded text-white font-bold">LVL {level}</span>
                 </div>
                 {/* Hearts */}
                 <div className="flex mt-1">
                    {Array.from({length: maxHp}).map((_, i) => (
                       <span key={i} className={`text-xl ${i < currentHp ? 'grayscale-0' : 'grayscale opacity-30'}`}>❤️</span>
                    ))}
                 </div>
              </div>

              {/* Perks List */}
              <div className="flex flex-col gap-1 items-end">
                 {activePerks.map((p, i) => (
                    <div key={i} className="bg-black/40 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 backdrop-blur-sm border border-white/20">
                       <span>{p.icon}</span>
                       <span className="max-w-[80px] truncate hidden sm:inline">{p.name}</span>
                    </div>
                 ))}
              </div>
           </div>

           {/* XP Bar */}
           <div className="absolute bottom-[50px] left-4 right-4 h-2 bg-black/50 rounded-full overflow-hidden border border-white/20 max-w-3xl mx-auto">
              <div 
                 className="h-full bg-yellow-400 transition-all duration-300"
                 style={{ width: `${(xp / LEVEL_UP_XP_REQ) * 100}%` }}
              ></div>
           </div>
        </div>

        {/* Overlays */}
        {gameState === GameState.START && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-50 backdrop-blur-[2px]">
            <h1 className="text-8xl text-yellow-400 font-bold pixel-text mb-4 animate-bounce drop-shadow-[6px_6px_0_#000]">FLAPPY ROGUE</h1>
            <div className="bg-slate-900 text-white p-8 rounded-xl border-4 border-slate-700 shadow-xl text-center min-w-[300px]">
               <p className="text-2xl mb-6 font-bold animate-pulse text-yellow-200">PRESS SPACE TO START</p>
               <div className="text-lg text-slate-400 space-y-2">
                  <p>❤️ Avoid Pipes & Ground</p>
                  <p>🟡 Collect Orbs for XP</p>
                  <p>⚡ Level Up & Get Broken Perks</p>
               </div>
            </div>
          </div>
        )}

        {gameState === GameState.RESUMING && (
           <div className="absolute inset-0 flex items-center justify-center z-50 bg-black/20 backdrop-blur-[1px]">
             <span key={countdown} className="text-9xl font-bold text-white pixel-text drop-shadow-[0_0_20px_rgba(0,0,0,0.8)] animate-ping duration-75">
               {countdown}
             </span>
           </div>
        )}

        {gameState === GameState.LEVEL_UP && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-50 p-4">
             <h2 className="text-6xl text-yellow-300 font-bold pixel-text mb-8 drop-shadow-md">LEVEL {level + 1}</h2>
             <p className="text-white mb-6 text-xl">Choose a Perk:</p>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl pointer-events-auto px-6">
               {offeredPerks.map(perk => (
                 <button
                   key={perk.id}
                   onClick={() => selectPerk(perk)}
                   className={`
                     relative flex flex-col items-center justify-center text-center gap-4 p-8 rounded-xl border-b-8 active:border-b-0 active:translate-y-2 transition-all group overflow-hidden h-64
                     ${perk.rarity === 'common' ? 'bg-slate-200 border-slate-400 text-slate-900' : ''}
                     ${perk.rarity === 'rare' ? 'bg-blue-100 border-blue-400 text-blue-900' : ''}
                     ${perk.rarity === 'legendary' ? 'bg-amber-100 border-amber-400 text-amber-900' : ''}
                   `}
                 >
                   <div className="absolute right-0 top-0 opacity-10 text-9xl rotate-12 -mr-8 -mt-4 group-hover:scale-110 transition-transform">{perk.icon}</div>
                   <span className="text-6xl z-10 drop-shadow-sm mb-2">{perk.icon}</span>
                   <div className="z-10 w-full">
                     <div className="font-bold uppercase flex items-center justify-center gap-2 text-xl mb-2">
                       {perk.name}
                       <span className="text-xs px-2 py-1 bg-black/10 rounded-full font-extrabold tracking-wide uppercase">{perk.rarity}</span>
                     </div>
                     <div className="text-base opacity-90 leading-tight font-medium">{perk.description}</div>
                   </div>
                 </button>
               ))}
             </div>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-950/90 z-50 backdrop-blur-sm pointer-events-auto">
            <h2 className="text-8xl text-white font-bold pixel-text mb-4 drop-shadow-[6px_6px_0_#000]">GAME OVER</h2>

            <div className="bg-slate-100 text-slate-900 p-8 rounded-xl w-80 text-center border-8 border-slate-900 mb-8 shadow-2xl transform scale-125">
              <div className="flex justify-between mb-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Score</span>
                <span className="text-4xl font-bold">{score}</span>
              </div>
              <div className="flex justify-between border-t-4 border-slate-300 pt-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Best</span>
                <span className="text-4xl font-bold text-orange-600">{Math.max(score, highScore)}</span>
              </div>
              <div className="mt-6 text-sm text-slate-400 font-mono">
                 Lvl {level} • {activePerks.length} Perks
              </div>
            </div>

            <button 
              onClick={resetGame}
              className="bg-green-500 hover:bg-green-600 text-white text-3xl font-bold py-6 px-16 rounded-2xl shadow-[0_8px_0_0_rgba(21,128,61,1)] active:shadow-none active:translate-y-2 transition-all mt-4"
            >
              RETRY
            </button>
          </div>
        )}

      </div>
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GameState, PhysicsConfig, PipeEntity, BirdState, Perk } from '../types';
import { 
  GAME_WIDTH, 
  GAME_HEIGHT, 
  INITIAL_PHYSICS, 
  BIRD_SIZE, 
  PIPE_WIDTH, 
  GROUND_HEIGHT, 
  AVAILABLE_PERKS, 
  LEVEL_UP_XP_REQ,
  PIPE_POOL_SIZE,
  ORB_SIZE
} from '../constants';

const GameEngine: React.FC = () => {
  // --- React State (UI Only) ---
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [score, setScore] = useState(0);
  const [xp, setXp] = useState(0);
  const [level, setLevel] = useState(1);
  const [highScore, setHighScore] = useState(0);
  const [activePerks, setActivePerks] = useState<Perk[]>([]);
  const [offeredPerks, setOfferedPerks] = useState<Perk[]>([]);
  const [currentHp, setCurrentHp] = useState(1);
  const [maxHp, setMaxHp] = useState(1);
  const [countdown, setCountdown] = useState(3);

  // --- Refs (Physics & Direct DOM Access) ---
  const birdRef = useRef<BirdState>({ 
    y: GAME_HEIGHT / 2, 
    velocity: 0, 
    rotation: 0, 
    scale: 1, 
    hp: 1, 
    maxHp: 1, 
    isInvulnerable: false, 
    invulnTimer: 0 
  });

  const physicsConfigRef = useRef<PhysicsConfig>({ ...INITIAL_PHYSICS });
  const pipesRef = useRef<PipeEntity[]>([]);
  const frameRef = useRef<number>(0);
  const lastTimeRef = useRef<number>(0);
  const activePerksRef = useRef<Set<string>>(new Set()); // Faster lookups

  // DOM Refs (For direct manipulation without React render)
  const birdDomRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pipePoolRefs = useRef<(HTMLDivElement | null)[]>([]); // Array of refs to pipe elements

  // --- Engine Logic ---

  const resetGame = () => {
    birdRef.current = { 
      y: GAME_HEIGHT / 2, 
      velocity: 0, 
      rotation: 0, 
      scale: 1, 
      hp: 1, 
      maxHp: 1, 
      isInvulnerable: false, 
      invulnTimer: 0 
    };
    pipesRef.current = [];
    physicsConfigRef.current = { ...INITIAL_PHYSICS };
    activePerksRef.current.clear();

    // Reset Pool Styles
    pipePoolRefs.current.forEach(el => {
      if (el) el.style.transform = `translate3d(-200px, 0, 0)`; // Move offscreen
    });

    setScore(0);
    setXp(0);
    setLevel(1);
    setActivePerks([]);
    setCurrentHp(1);
    setMaxHp(1);
    setGameState(GameState.START);
  };

  const spawnPipe = (offset: number) => {
    // Find an available pool index that isn't currently used by an active pipe
    const usedIndices = new Set(pipesRef.current.map(p => p.poolIndex));
    let poolIndex = -1;
    for (let i = 0; i < PIPE_POOL_SIZE; i++) {
      if (!usedIndices.has(i)) {
        poolIndex = i;
        break;
      }
    }

    if (poolIndex === -1) return; // Should not happen with correct pool size vs spacing

    const config = physicsConfigRef.current;
    const minPipeHeight = 50;
    const maxPipeHeight = GAME_HEIGHT - GROUND_HEIGHT - config.gapSize - minPipeHeight;
    const randomHeight = Math.floor(Math.random() * (maxPipeHeight - minPipeHeight + 1)) + minPipeHeight;

    // 30% chance for an Orb
    const hasOrb = Math.random() < 0.3;
    const orbY = randomHeight + (config.gapSize / 2) - (ORB_SIZE / 2);

    pipesRef.current.push({
      id: Date.now() + Math.random(),
      x: offset,
      topHeight: randomHeight,
      passed: false,
      poolIndex,
      hasOrb,
      orbY,
      orbCollected: false
    });
  };

  const jump = useCallback((e?: React.SyntheticEvent | Event) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (gameState === GameState.PLAYING) {
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
    } else if (gameState === GameState.START) {
      setGameState(GameState.PLAYING);
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
      lastTimeRef.current = performance.now();
    }
  }, [gameState]);

  const takeDamage = () => {
    const bird = birdRef.current;
    if (bird.isInvulnerable) return;

    bird.hp -= 1;
    setCurrentHp(bird.hp);

    if (bird.hp <= 0) {
      setGameState(GameState.GAME_OVER);
      setHighScore(prev => Math.max(prev, score));
    } else {
      // Invulnerability frames
      bird.isInvulnerable = true;
      bird.invulnTimer = 60; // ~1 second at 60fps

      // Visual feedback
      if (birdDomRef.current) {
        birdDomRef.current.style.filter = 'brightness(500%) sepia(100%) hue-rotate(-50deg) saturate(600%)';
        setTimeout(() => {
          if (birdDomRef.current) birdDomRef.current.style.filter = 'none';
        }, 100);
      }
    }
  };

  const gainXp = (amount: number) => {
    setXp(prev => {
      const nextXp = prev + amount;
      if (nextXp >= LEVEL_UP_XP_REQ) {
        // Schedule level up logic outside render loop to avoid clashes
        requestAnimationFrame(() => {
           setGameState(GameState.LEVEL_UP);
           // Generate Perks
           const available = AVAILABLE_PERKS.filter(p => {
             // Filter out unique perks if already have them? (For now allow stacking some)
             if (p.id === 'tiny_bird' && activePerksRef.current.has('tiny_bird')) return false;
             return true;
           });
           const shuffled = [...available].sort(() => 0.5 - Math.random());
           setOfferedPerks(shuffled.slice(0, 3));
        });
        return 0; // Reset XP or keep overflow? Let's reset for simple levels
      }
      return nextXp;
    });
  };

  const selectPerk = (perk: Perk) => {
    setActivePerks(prev => [...prev, perk]);
    activePerksRef.current.add(perk.id);

    // Apply Physics
    if (perk.apply) {
      physicsConfigRef.current = perk.apply(physicsConfigRef.current);
    }

    // Apply Stats
    if (perk.id === 'vitality') {
      birdRef.current.maxHp += 1;
      birdRef.current.hp += 1;
      setMaxHp(prev => prev + 1);
      setCurrentHp(prev => prev + 1);
    }
    if (perk.id === 'tiny_bird') {
      birdRef.current.scale = 0.7;
    }

    setLevel(l => l + 1);

    // Instead of PLAYING immediately, go to RESUMING
    setGameState(GameState.RESUMING);
  };

  // Countdown Logic
  useEffect(() => {
    if (gameState === GameState.RESUMING) {
      setCountdown(3);
      const timer = setInterval(() => {
        setCountdown(prev => {
          if (prev <= 1) {
            clearInterval(timer);
            setGameState(GameState.PLAYING);
            lastTimeRef.current = performance.now(); // Reset time to prevent big physics jump
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [gameState]);

  // --- Main Game Loop (Optimized) ---
  const update = useCallback((time: number) => {
    // Delta time calculation for smooth physics regardless of framerate
    const delta = time - lastTimeRef.current;
    lastTimeRef.current = time;

    // Cap dt to prevent huge jumps if tab was inactive
    const dt = Math.min(delta / 16.67, 2.0); 

    if (gameState === GameState.START) {
      // Hover animation
      const hoverY = (GAME_HEIGHT / 2) + Math.sin(time / 300) * 12;
      if (birdDomRef.current) {
        birdDomRef.current.style.transform = `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${hoverY}px, 0) rotate(0deg)`;
      }
      frameRef.current = requestAnimationFrame(update);
      return;
    }

    // Handle Resuming State - Render Static
    if (gameState === GameState.RESUMING) {
       // Keep rendering the bird static so it doesn't disappear
       if (birdDomRef.current) {
          birdDomRef.current.style.transform = 
            `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(birdRef.current.y - (BIRD_SIZE/2))}px, 0) ` + 
            `rotate(${Math.round(birdRef.current.rotation)}deg) scale(${birdRef.current.scale})`;
       }
       frameRef.current = requestAnimationFrame(update);
       return;
    }

    if (gameState !== GameState.PLAYING) {
      return; // Stop loop if paused/gameover
    }

    const config = physicsConfigRef.current;
    const bird = birdRef.current;
    const pipes = pipesRef.current;

    // --- Physics ---

    // Bird Gravity
    bird.velocity += config.gravity * dt;
    bird.y += bird.velocity * dt;

    // Floor Collision
    if (bird.y >= GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2)) {
      bird.y = GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2);
      takeDamage();
      if (bird.hp > 0) bird.velocity = config.jumpStrength * 1.2; // Bounce if alive
    }
    // Ceiling
    if (bird.y < 0) {
      bird.y = 0;
      bird.velocity = 0;
    }

    // Invulnerability Timer
    if (bird.isInvulnerable) {
      bird.invulnTimer -= dt;
      if (bird.invulnTimer <= 0) bird.isInvulnerable = false;
    }

    // Rotation
    bird.rotation = Math.min(Math.max(bird.velocity * 3.5, -25), 90);

    // --- Pipe Management ---

    // Spawn Logic
    const lastPipe = pipes[pipes.length - 1];
    const spawnDist = config.spawnRate;
    if (!lastPipe || (GAME_WIDTH - lastPipe.x) > spawnDist) {
      spawnPipe(GAME_WIDTH);
    }

    // Move & Collide
    for (let i = pipes.length - 1; i >= 0; i--) {
      const p = pipes[i];
      p.x -= config.pipeSpeed * dt;

      // Magnet Logic
      if (p.hasOrb && !p.orbCollected && activePerksRef.current.has('magnet')) {
         const dx = (GAME_WIDTH / 2) - (p.x + PIPE_WIDTH/2);
         const dy = bird.y - p.orbY;
         const dist = Math.sqrt(dx*dx + dy*dy);
         if (dist < 200) {
            p.orbY += dy * 0.1 * dt; // Move towards bird Y
            // Visual X movement is tricky since pipe controls X, but we can simulate it strictly visually or just Y
         }
      }

      // Remove off-screen
      if (p.x + PIPE_WIDTH < -50) {
        // Move DOM element offscreen to hide it
        const domEl = pipePoolRefs.current[p.poolIndex];
        if (domEl) domEl.style.transform = `translate3d(-200px, 0, 0)`;

        pipes.splice(i, 1);
        continue;
      }

      // Collision Boxes
      const birdRadius = (BIRD_SIZE * bird.scale) / 2;
      const birdX = GAME_WIDTH / 2;

      // Rect-Circle Collision (Simplified to Box-Box for performance)
      const birdLeft = birdX - birdRadius + 4;
      const birdRight = birdX + birdRadius - 4;
      const birdTop = bird.y - birdRadius + 4;
      const birdBottom = bird.y + birdRadius - 4;

      const pipeLeft = p.x;
      const pipeRight = p.x + PIPE_WIDTH;

      // Pipe Collision
      if (birdRight > pipeLeft && birdLeft < pipeRight) {
        const hitTop = birdTop < p.topHeight;
        const hitBottom = birdBottom > (p.topHeight + config.gapSize);

        if (hitTop || hitBottom) {
           takeDamage();
        }
      }

      // Orb Collision
      if (p.hasOrb && !p.orbCollected) {
         const orbX = p.x + (PIPE_WIDTH/2);
         const orbY = p.orbY;
         const dx = birdX - orbX;
         const dy = bird.y - orbY;
         if (Math.sqrt(dx*dx + dy*dy) < (BIRD_SIZE + ORB_SIZE)/2) {
            p.orbCollected = true;
            gainXp(1); // Bonus XP
         }
      }

      // Passing Score
      if (!p.passed && p.x + PIPE_WIDTH < birdLeft) {
        p.passed = true;
        setScore(s => s + 1);
        gainXp(1);
      }
    }

    // --- Render Updates (Direct DOM) ---

    // Bird
    if (birdDomRef.current) {
      birdDomRef.current.style.transform = 
        `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(bird.y - (BIRD_SIZE/2))}px, 0) ` + 
        `rotate(${Math.round(bird.rotation)}deg) scale(${bird.scale})`;

      // Blink effect
      birdDomRef.current.style.opacity = bird.isInvulnerable && Math.floor(time / 100) % 2 === 0 ? '0.5' : '1';
    }

    // Pipes
    pipes.forEach(p => {
      const el = pipePoolRefs.current[p.poolIndex];
      if (el) {
        el.style.transform = `translate3d(${Math.round(p.x)}px, 0, 0)`;

        // Only need to set height if it changed (new pipe assignment)
        if (el.dataset.lastId !== String(p.id)) {
           el.dataset.lastId = String(p.id);

           // Update Top Pipe Height
           const topPipe = el.firstElementChild as HTMLElement;
           if (topPipe) topPipe.style.height = `${p.topHeight}px`;

           // Update Bottom Pipe Position/Height
           const bottomPipe = el.lastElementChild?.previousElementSibling as HTMLElement; // Assuming structure
           if (bottomPipe) {
             bottomPipe.style.top = `${p.topHeight + config.gapSize}px`;
             bottomPipe.style.height = `${GAME_HEIGHT - GROUND_HEIGHT - (p.topHeight + config.gapSize)}px`;
           }

           // Update Orb
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) {
              orb.style.display = p.hasOrb ? 'block' : 'none';
              orb.style.top = `${p.orbY}px`;
           }
        }

        // Update Orb visibility if collected
        if (p.orbCollected) {
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.display = 'none';
        } else if (p.hasOrb && activePerksRef.current.has('magnet')) {
           // Update dynamic orb Y if magnet is active
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.top = `${p.orbY}px`;
        }
      }
    });

    frameRef.current = requestAnimationFrame(update);
  }, [gameState]); // Dependencies minimized

  // Start/Stop Loop
  useEffect(() => {
    if (gameState === GameState.PLAYING || gameState === GameState.START || gameState === GameState.RESUMING) {
      lastTimeRef.current = performance.now();
      frameRef.current = requestAnimationFrame(update);
    }
    return () => cancelAnimationFrame(frameRef.current);
  }, [gameState, update]);

  // Input Listeners
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.code === 'Space') jump(e);
    };
    // Passive: false is crucial for touch to prevent scrolling and ensure immediate response
    window.addEventListener('keydown', handler);
    window.addEventListener('touchstart', jump as any, { passive: false });
    window.addEventListener('mousedown', jump as any);

    return () => {
      window.removeEventListener('keydown', handler);
      window.removeEventListener('touchstart', jump as any);
      window.removeEventListener('mousedown', jump as any);
    };
  }, [jump]);

  // Initial Pool Creation
  // We render a static pool of pipes that are recycled.
  const pipePool = useMemo(() => {
    return Array.from({ length: PIPE_POOL_SIZE }).map((_, i) => i);
  }, []);

  return (
    <div className="w-screen h-screen overflow-hidden bg-slate-950 font-mono select-none">

      {/* Game Stage */}
      <div 
        ref={containerRef}
        className="relative w-full h-full"
        style={{ width: GAME_WIDTH, height: GAME_HEIGHT, background: 'linear-gradient(to bottom, #4facfe 0%, #00f2fe 100%)' }}
      >
        {/* Background Elements (Static) */}
        <div className="absolute top-[10%] left-[5%] opacity-50 text-white text-6xl pointer-events-none">☁️</div>
        <div className="absolute top-[20%] left-[40%] opacity-40 text-white text-5xl pointer-events-none">☁️</div>
        <div className="absolute top-[5%] left-[70%] opacity-60 text-white text-4xl pointer-events-none">☁️</div>
        <div className="absolute top-[15%] left-[90%] opacity-30 text-white text-5xl pointer-events-none">☁️</div>

        {/* --- Render Pipe Pool --- */}
        {pipePool.map((i) => (
          <div
            key={i}
            ref={el => { pipePoolRefs.current[i] = el; }}
            className="absolute top-0 left-0 w-full h-full pointer-events-none will-change-transform"
            style={{ transform: 'translate3d(-200px, 0, 0)' }} // Start hidden
          >
            {/* Top Pipe */}
            <div className="absolute left-0 top-0 bg-green-500 border-x-4 border-b-4 border-green-800 transition-none w-[52px]">
               <div className="absolute bottom-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* Bottom Pipe */}
            <div className="absolute left-0 bg-green-500 border-x-4 border-t-4 border-green-800 transition-none w-[52px]">
               <div className="absolute top-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* XP Orb */}
            <div className="orb absolute left-[14px] w-6 h-6 rounded-full bg-yellow-300 border-2 border-yellow-500 shadow-[0_0_10px_rgba(253,224,71,0.8)] animate-pulse hidden z-10"></div>
          </div>
        ))}

        {/* Ground */}
        <div 
          className="absolute bottom-0 w-full bg-[#ded895] border-t-4 border-[#cbb968] z-20"
          style={{ height: GROUND_HEIGHT }}
        >
           <div className="w-full h-4 bg-[url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAQAAAAECAYAAACp8Z5+AAAAIklEQVQIW2NkQAKrVq36zwjjgzjIHFBMkCdYAL4YxAHLAAAYDBQz5/tq+AAAAABJRU5ErkJggg==')] opacity-30 animate-pulse"></div>
        </div>

        {/* Bird (Direct DOM) */}
        <div 
          ref={birdDomRef}
          className="absolute top-0 left-0 z-30 flex items-center justify-center will-change-transform pointer-events-none"
          style={{
            width: BIRD_SIZE,
            height: BIRD_SIZE,
            transform: `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${(GAME_HEIGHT/2)}px, 0)`
          }}
        >
          <span className="text-3xl filter drop-shadow-md">🐥</span>
        </div>

        {/* UI Layer (React) */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-40 p-4">
           {/* HUD */}
           <div className="flex justify-between items-start">
              <div>
                 <div className="flex items-baseline gap-2">
                    <span className="text-5xl font-bold pixel-text text-white drop-shadow-md leading-none">{score}</span>
                    <span className="text-sm bg-black/40 px-2 py-0.5 rounded text-white font-bold">LVL {level}</span>
                 </div>
                 {/* Hearts */}
                 <div className="flex mt-1">
                    {Array.from({length: maxHp}).map((_, i) => (
                       <span key={i} className={`text-xl ${i < currentHp ? 'grayscale-0' : 'grayscale opacity-30'}`}>❤️</span>
                    ))}
                 </div>
              </div>

              {/* Perks List */}
              <div className="flex flex-col gap-1 items-end">
                 {activePerks.map((p, i) => (
                    <div key={i} className="bg-black/40 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 backdrop-blur-sm border border-white/20">
                       <span>{p.icon}</span>
                       <span className="max-w-[80px] truncate hidden sm:inline">{p.name}</span>
                    </div>
                 ))}
              </div>
           </div>

           {/* XP Bar */}
           <div className="absolute bottom-[50px] left-4 right-4 h-2 bg-black/50 rounded-full overflow-hidden border border-white/20 max-w-3xl mx-auto">
              <div 
                 className="h-full bg-yellow-400 transition-all duration-300"
                 style={{ width: `${(xp / LEVEL_UP_XP_REQ) * 100}%` }}
              ></div>
           </div>
        </div>

        {/* Overlays */}
        {gameState === GameState.START && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-50 backdrop-blur-[2px]">
            <h1 className="text-8xl text-yellow-400 font-bold pixel-text mb-4 animate-bounce drop-shadow-[6px_6px_0_#000]">FLAPPY ROGUE</h1>
            <div className="bg-slate-900 text-white p-8 rounded-xl border-4 border-slate-700 shadow-xl text-center min-w-[300px]">
               <p className="text-2xl mb-6 font-bold animate-pulse text-yellow-200">PRESS SPACE TO START</p>
               <div className="text-lg text-slate-400 space-y-2">
                  <p>❤️ Avoid Pipes & Ground</p>
                  <p>🟡 Collect Orbs for XP</p>
                  <p>⚡ Level Up & Get Broken Perks</p>
               </div>
            </div>
          </div>
        )}

        {gameState === GameState.RESUMING && (
           <div className="absolute inset-0 flex items-center justify-center z-50 bg-black/20 backdrop-blur-[1px]">
             <span key={countdown} className="text-9xl font-bold text-white pixel-text drop-shadow-[0_0_20px_rgba(0,0,0,0.8)] animate-ping duration-75">
               {countdown}
             </span>
           </div>
        )}

        {gameState === GameState.LEVEL_UP && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-50 p-4">
             <h2 className="text-6xl text-yellow-300 font-bold pixel-text mb-8 drop-shadow-md">LEVEL {level + 1}</h2>
             <p className="text-white mb-6 text-xl">Choose a Perk:</p>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl pointer-events-auto px-6">
               {offeredPerks.map(perk => (
                 <button
                   key={perk.id}
                   onClick={() => selectPerk(perk)}
                   className={`
                     relative flex flex-col items-center justify-center text-center gap-4 p-8 rounded-xl border-b-8 active:border-b-0 active:translate-y-2 transition-all group overflow-hidden h-64
                     ${perk.rarity === 'common' ? 'bg-slate-200 border-slate-400 text-slate-900' : ''}
                     ${perk.rarity === 'rare' ? 'bg-blue-100 border-blue-400 text-blue-900' : ''}
                     ${perk.rarity === 'legendary' ? 'bg-amber-100 border-amber-400 text-amber-900' : ''}
                   `}
                 >
                   <div className="absolute right-0 top-0 opacity-10 text-9xl rotate-12 -mr-8 -mt-4 group-hover:scale-110 transition-transform">{perk.icon}</div>
                   <span className="text-6xl z-10 drop-shadow-sm mb-2">{perk.icon}</span>
                   <div className="z-10 w-full">
                     <div className="font-bold uppercase flex items-center justify-center gap-2 text-xl mb-2">
                       {perk.name}
                       <span className="text-xs px-2 py-1 bg-black/10 rounded-full font-extrabold tracking-wide uppercase">{perk.rarity}</span>
                     </div>
                     <div className="text-base opacity-90 leading-tight font-medium">{perk.description}</div>
                   </div>
                 </button>
               ))}
             </div>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-950/90 z-50 backdrop-blur-sm pointer-events-auto">
            <h2 className="text-8xl text-white font-bold pixel-text mb-4 drop-shadow-[6px_6px_0_#000]">GAME OVER</h2>

            <div className="bg-slate-100 text-slate-900 p-8 rounded-xl w-80 text-center border-8 border-slate-900 mb-8 shadow-2xl transform scale-125">
              <div className="flex justify-between mb-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Score</span>
                <span className="text-4xl font-bold">{score}</span>
              </div>
              <div className="flex justify-between border-t-4 border-slate-300 pt-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Best</span>
                <span className="text-4xl font-bold text-orange-600">{Math.max(score, highScore)}</span>
              </div>
              <div className="mt-6 text-sm text-slate-400 font-mono">
                 Lvl {level} • {activePerks.length} Perks
              </div>
            </div>

            <button 
              onClick={resetGame}
              className="bg-green-500 hover:bg-green-600 text-white text-3xl font-bold py-6 px-16 rounded-2xl shadow-[0_8px_0_0_rgba(21,128,61,1)] active:shadow-none active:translate-y-2 transition-all mt-4"
            >
              RETRY
            </button>
          </div>
        )}

      </div>
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GameState, PhysicsConfig, PipeEntity, BirdState, Perk } from '../types';
import { 
  GAME_WIDTH, 
  GAME_HEIGHT, 
  INITIAL_PHYSICS, 
  BIRD_SIZE, 
  PIPE_WIDTH, 
  GROUND_HEIGHT, 
  AVAILABLE_PERKS, 
  LEVEL_UP_XP_REQ,
  PIPE_POOL_SIZE,
  ORB_SIZE
} from '../constants';

const GameEngine: React.FC = () => {
  // --- React State (UI Only) ---
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [score, setScore] = useState(0);
  const [xp, setXp] = useState(0);
  const [level, setLevel] = useState(1);
  const [highScore, setHighScore] = useState(0);
  const [activePerks, setActivePerks] = useState<Perk[]>([]);
  const [offeredPerks, setOfferedPerks] = useState<Perk[]>([]);
  const [currentHp, setCurrentHp] = useState(1);
  const [maxHp, setMaxHp] = useState(1);
  const [countdown, setCountdown] = useState(3);

  // --- Refs (Physics & Direct DOM Access) ---
  const birdRef = useRef<BirdState>({ 
    y: GAME_HEIGHT / 2, 
    velocity: 0, 
    rotation: 0, 
    scale: 1, 
    hp: 1, 
    maxHp: 1, 
    isInvulnerable: false, 
    invulnTimer: 0 
  });

  const physicsConfigRef = useRef<PhysicsConfig>({ ...INITIAL_PHYSICS });
  const pipesRef = useRef<PipeEntity[]>([]);
  const frameRef = useRef<number>(0);
  const lastTimeRef = useRef<number>(0);
  const activePerksRef = useRef<Set<string>>(new Set()); // Faster lookups

  // DOM Refs (For direct manipulation without React render)
  const birdDomRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pipePoolRefs = useRef<(HTMLDivElement | null)[]>([]); // Array of refs to pipe elements

  // --- Engine Logic ---

  const resetGame = () => {
    birdRef.current = { 
      y: GAME_HEIGHT / 2, 
      velocity: 0, 
      rotation: 0, 
      scale: 1, 
      hp: 1, 
      maxHp: 1, 
      isInvulnerable: false, 
      invulnTimer: 0 
    };
    pipesRef.current = [];
    physicsConfigRef.current = { ...INITIAL_PHYSICS };
    activePerksRef.current.clear();

    // Reset Pool Styles
    pipePoolRefs.current.forEach(el => {
      if (el) el.style.transform = `translate3d(-200px, 0, 0)`; // Move offscreen
    });

    setScore(0);
    setXp(0);
    setLevel(1);
    setActivePerks([]);
    setCurrentHp(1);
    setMaxHp(1);
    setGameState(GameState.START);
  };

  const spawnPipe = (offset: number) => {
    // Find an available pool index that isn't currently used by an active pipe
    const usedIndices = new Set(pipesRef.current.map(p => p.poolIndex));
    let poolIndex = -1;
    for (let i = 0; i < PIPE_POOL_SIZE; i++) {
      if (!usedIndices.has(i)) {
        poolIndex = i;
        break;
      }
    }

    if (poolIndex === -1) return; // Should not happen with correct pool size vs spacing

    const config = physicsConfigRef.current;
    const minPipeHeight = 50;
    const maxPipeHeight = GAME_HEIGHT - GROUND_HEIGHT - config.gapSize - minPipeHeight;
    const randomHeight = Math.floor(Math.random() * (maxPipeHeight - minPipeHeight + 1)) + minPipeHeight;

    // 30% chance for an Orb
    const hasOrb = Math.random() < 0.3;
    const orbY = randomHeight + (config.gapSize / 2) - (ORB_SIZE / 2);

    pipesRef.current.push({
      id: Date.now() + Math.random(),
      x: offset,
      topHeight: randomHeight,
      passed: false,
      poolIndex,
      hasOrb,
      orbY,
      orbCollected: false
    });
  };

  const jump = useCallback((e?: React.SyntheticEvent | Event) => {
    // Fix: Ignore click/touch if interacting with a button (e.g. Retry or Perks)
    if (e && e.target instanceof Element && (e.target.tagName === 'BUTTON' || e.target.closest('button'))) {
      return;
    }

    if (gameState === GameState.PLAYING) {
      if (e) {
        e.preventDefault();
        e.stopPropagation();
      }
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
    } else if (gameState === GameState.START) {
      if (e) {
        e.preventDefault();
        e.stopPropagation();
      }
      setGameState(GameState.PLAYING);
      birdRef.current.velocity = physicsConfigRef.current.jumpStrength;
      lastTimeRef.current = performance.now();
    }
    // For other states (GAME_OVER, LEVEL_UP), do NOT prevent default so buttons work
  }, [gameState]);

  const takeDamage = () => {
    const bird = birdRef.current;
    if (bird.isInvulnerable) return;

    bird.hp -= 1;
    setCurrentHp(bird.hp);

    if (bird.hp <= 0) {
      setGameState(GameState.GAME_OVER);
      setHighScore(prev => Math.max(prev, score));
    } else {
      // Invulnerability frames
      bird.isInvulnerable = true;
      bird.invulnTimer = 60; // ~1 second at 60fps

      // Visual feedback
      if (birdDomRef.current) {
        birdDomRef.current.style.filter = 'brightness(500%) sepia(100%) hue-rotate(-50deg) saturate(600%)';
        setTimeout(() => {
          if (birdDomRef.current) birdDomRef.current.style.filter = 'none';
        }, 100);
      }
    }
  };

  const gainXp = (amount: number) => {
    setXp(prev => {
      const nextXp = prev + amount;
      if (nextXp >= LEVEL_UP_XP_REQ) {
        // Schedule level up logic outside render loop to avoid clashes
        requestAnimationFrame(() => {
           setGameState(GameState.LEVEL_UP);
           // Generate Perks
           const available = AVAILABLE_PERKS.filter(p => {
             // Filter out unique perks if already have them? (For now allow stacking some)
             if (p.id === 'tiny_bird' && activePerksRef.current.has('tiny_bird')) return false;
             return true;
           });
           const shuffled = [...available].sort(() => 0.5 - Math.random());
           setOfferedPerks(shuffled.slice(0, 3));
        });
        return 0; // Reset XP or keep overflow? Let's reset for simple levels
      }
      return nextXp;
    });
  };

  const selectPerk = (perk: Perk) => {
    setActivePerks(prev => [...prev, perk]);
    activePerksRef.current.add(perk.id);

    // Apply Physics
    if (perk.apply) {
      physicsConfigRef.current = perk.apply(physicsConfigRef.current);
    }

    // Apply Stats
    if (perk.id === 'vitality') {
      birdRef.current.maxHp += 1;
      birdRef.current.hp += 1;
      setMaxHp(prev => prev + 1);
      setCurrentHp(prev => prev + 1);
    }
    if (perk.id === 'tiny_bird') {
      birdRef.current.scale = 0.7;
    }

    setLevel(l => l + 1);

    // Instead of PLAYING immediately, go to RESUMING
    setGameState(GameState.RESUMING);
  };

  // Countdown Logic
  useEffect(() => {
    if (gameState === GameState.RESUMING) {
      setCountdown(3);
      const timer = setInterval(() => {
        setCountdown(prev => {
          if (prev <= 1) {
            clearInterval(timer);
            setGameState(GameState.PLAYING);
            lastTimeRef.current = performance.now(); // Reset time to prevent big physics jump
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [gameState]);

  // --- Main Game Loop (Optimized) ---
  const update = useCallback((time: number) => {
    // Delta time calculation for smooth physics regardless of framerate
    const delta = time - lastTimeRef.current;
    lastTimeRef.current = time;

    // Cap dt to prevent huge jumps if tab was inactive
    const dt = Math.min(delta / 16.67, 2.0); 

    if (gameState === GameState.START) {
      // Hover animation
      const hoverY = (GAME_HEIGHT / 2) + Math.sin(time / 300) * 12;
      if (birdDomRef.current) {
        birdDomRef.current.style.transform = `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${hoverY}px, 0) rotate(0deg)`;
      }
      frameRef.current = requestAnimationFrame(update);
      return;
    }

    // Handle Resuming State - Render Static
    if (gameState === GameState.RESUMING) {
       // Keep rendering the bird static so it doesn't disappear
       if (birdDomRef.current) {
          birdDomRef.current.style.transform = 
            `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(birdRef.current.y - (BIRD_SIZE/2))}px, 0) ` + 
            `rotate(${Math.round(birdRef.current.rotation)}deg) scale(${birdRef.current.scale})`;
       }
       frameRef.current = requestAnimationFrame(update);
       return;
    }

    if (gameState !== GameState.PLAYING) {
      return; // Stop loop if paused/gameover
    }

    const config = physicsConfigRef.current;
    const bird = birdRef.current;
    const pipes = pipesRef.current;

    // --- Physics ---

    // Bird Gravity
    bird.velocity += config.gravity * dt;
    bird.y += bird.velocity * dt;

    // Floor Collision
    if (bird.y >= GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2)) {
      bird.y = GAME_HEIGHT - GROUND_HEIGHT - (BIRD_SIZE * bird.scale / 2);
      takeDamage();
      if (bird.hp > 0) bird.velocity = config.jumpStrength * 1.2; // Bounce if alive
    }
    // Ceiling
    if (bird.y < 0) {
      bird.y = 0;
      bird.velocity = 0;
    }

    // Invulnerability Timer
    if (bird.isInvulnerable) {
      bird.invulnTimer -= dt;
      if (bird.invulnTimer <= 0) bird.isInvulnerable = false;
    }

    // Rotation
    bird.rotation = Math.min(Math.max(bird.velocity * 3.5, -25), 90);

    // --- Pipe Management ---

    // Spawn Logic
    const lastPipe = pipes[pipes.length - 1];
    const spawnDist = config.spawnRate;
    if (!lastPipe || (GAME_WIDTH - lastPipe.x) > spawnDist) {
      spawnPipe(GAME_WIDTH);
    }

    // Move & Collide
    for (let i = pipes.length - 1; i >= 0; i--) {
      const p = pipes[i];
      p.x -= config.pipeSpeed * dt;

      // Magnet Logic
      if (p.hasOrb && !p.orbCollected && activePerksRef.current.has('magnet')) {
         const dx = (GAME_WIDTH / 2) - (p.x + PIPE_WIDTH/2);
         const dy = bird.y - p.orbY;
         const dist = Math.sqrt(dx*dx + dy*dy);
         if (dist < 200) {
            p.orbY += dy * 0.1 * dt; // Move towards bird Y
            // Visual X movement is tricky since pipe controls X, but we can simulate it strictly visually or just Y
         }
      }

      // Remove off-screen
      if (p.x + PIPE_WIDTH < -50) {
        // Move DOM element offscreen to hide it
        const domEl = pipePoolRefs.current[p.poolIndex];
        if (domEl) domEl.style.transform = `translate3d(-200px, 0, 0)`;

        pipes.splice(i, 1);
        continue;
      }

      // Collision Boxes
      const birdRadius = (BIRD_SIZE * bird.scale) / 2;
      const birdX = GAME_WIDTH / 2;

      // Rect-Circle Collision (Simplified to Box-Box for performance)
      const birdLeft = birdX - birdRadius + 4;
      const birdRight = birdX + birdRadius - 4;
      const birdTop = bird.y - birdRadius + 4;
      const birdBottom = bird.y + birdRadius - 4;

      const pipeLeft = p.x;
      const pipeRight = p.x + PIPE_WIDTH;

      // Pipe Collision
      if (birdRight > pipeLeft && birdLeft < pipeRight) {
        const hitTop = birdTop < p.topHeight;
        const hitBottom = birdBottom > (p.topHeight + config.gapSize);

        if (hitTop || hitBottom) {
           takeDamage();
        }
      }

      // Orb Collision
      if (p.hasOrb && !p.orbCollected) {
         const orbX = p.x + (PIPE_WIDTH/2);
         const orbY = p.orbY;
         const dx = birdX - orbX;
         const dy = bird.y - orbY;
         if (Math.sqrt(dx*dx + dy*dy) < (BIRD_SIZE + ORB_SIZE)/2) {
            p.orbCollected = true;
            gainXp(1); // Bonus XP
         }
      }

      // Passing Score
      if (!p.passed && p.x + PIPE_WIDTH < birdLeft) {
        p.passed = true;
        setScore(s => s + 1);
        gainXp(1);
      }
    }

    // --- Render Updates (Direct DOM) ---

    // Bird
    if (birdDomRef.current) {
      birdDomRef.current.style.transform = 
        `translate3d(${Math.round((GAME_WIDTH/2) - (BIRD_SIZE/2))}px, ${Math.round(bird.y - (BIRD_SIZE/2))}px, 0) ` + 
        `rotate(${Math.round(bird.rotation)}deg) scale(${bird.scale})`;

      // Blink effect
      birdDomRef.current.style.opacity = bird.isInvulnerable && Math.floor(time / 100) % 2 === 0 ? '0.5' : '1';
    }

    // Pipes
    pipes.forEach(p => {
      const el = pipePoolRefs.current[p.poolIndex];
      if (el) {
        el.style.transform = `translate3d(${Math.round(p.x)}px, 0, 0)`;

        // Only need to set height if it changed (new pipe assignment)
        if (el.dataset.lastId !== String(p.id)) {
           el.dataset.lastId = String(p.id);

           // Update Top Pipe Height
           const topPipe = el.firstElementChild as HTMLElement;
           if (topPipe) topPipe.style.height = `${p.topHeight}px`;

           // Update Bottom Pipe Position/Height
           const bottomPipe = el.lastElementChild?.previousElementSibling as HTMLElement; // Assuming structure
           if (bottomPipe) {
             bottomPipe.style.top = `${p.topHeight + config.gapSize}px`;
             bottomPipe.style.height = `${GAME_HEIGHT - GROUND_HEIGHT - (p.topHeight + config.gapSize)}px`;
           }

           // Update Orb
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) {
              orb.style.display = p.hasOrb ? 'block' : 'none';
              orb.style.top = `${p.orbY}px`;
           }
        }

        // Update Orb visibility if collected
        if (p.orbCollected) {
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.display = 'none';
        } else if (p.hasOrb && activePerksRef.current.has('magnet')) {
           // Update dynamic orb Y if magnet is active
           const orb = el.querySelector('.orb') as HTMLElement;
           if (orb) orb.style.top = `${p.orbY}px`;
        }
      }
    });

    frameRef.current = requestAnimationFrame(update);
  }, [gameState]); // Dependencies minimized

  // Start/Stop Loop
  useEffect(() => {
    if (gameState === GameState.PLAYING || gameState === GameState.START || gameState === GameState.RESUMING) {
      lastTimeRef.current = performance.now();
      frameRef.current = requestAnimationFrame(update);
    }
    return () => cancelAnimationFrame(frameRef.current);
  }, [gameState, update]);

  // Input Listeners
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.code === 'Space') jump(e);
    };
    // Passive: false is crucial for touch to prevent scrolling and ensure immediate response
    window.addEventListener('keydown', handler);
    window.addEventListener('touchstart', jump as any, { passive: false });
    window.addEventListener('mousedown', jump as any);

    return () => {
      window.removeEventListener('keydown', handler);
      window.removeEventListener('touchstart', jump as any);
      window.removeEventListener('mousedown', jump as any);
    };
  }, [jump]);

  // Initial Pool Creation
  // We render a static pool of pipes that are recycled.
  const pipePool = useMemo(() => {
    return Array.from({ length: PIPE_POOL_SIZE }).map((_, i) => i);
  }, []);

  return (
    <div className="w-screen h-screen overflow-hidden bg-slate-950 font-mono select-none">

      {/* Game Stage */}
      <div 
        ref={containerRef}
        className="relative w-full h-full"
        style={{ width: GAME_WIDTH, height: GAME_HEIGHT, background: 'linear-gradient(to bottom, #4facfe 0%, #00f2fe 100%)' }}
      >
        {/* Background Elements (Static) */}
        <div className="absolute top-[10%] left-[5%] opacity-50 text-white text-6xl pointer-events-none">☁️</div>
        <div className="absolute top-[20%] left-[40%] opacity-40 text-white text-5xl pointer-events-none">☁️</div>
        <div className="absolute top-[5%] left-[70%] opacity-60 text-white text-4xl pointer-events-none">☁️</div>
        <div className="absolute top-[15%] left-[90%] opacity-30 text-white text-5xl pointer-events-none">☁️</div>

        {/* --- Render Pipe Pool --- */}
        {pipePool.map((i) => (
          <div
            key={i}
            ref={el => { pipePoolRefs.current[i] = el; }}
            className="absolute top-0 left-0 w-full h-full pointer-events-none will-change-transform"
            style={{ transform: 'translate3d(-200px, 0, 0)' }} // Start hidden
          >
            {/* Top Pipe */}
            <div className="absolute left-0 top-0 bg-green-500 border-x-4 border-b-4 border-green-800 transition-none w-[52px]">
               <div className="absolute bottom-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* Bottom Pipe */}
            <div className="absolute left-0 bg-green-500 border-x-4 border-t-4 border-green-800 transition-none w-[52px]">
               <div className="absolute top-0 left-[-4px] w-[calc(100%+8px)] h-6 bg-green-500 border-4 border-green-800"></div>
            </div>

            {/* XP Orb */}
            <div className="orb absolute left-[14px] w-6 h-6 rounded-full bg-yellow-300 border-2 border-yellow-500 shadow-[0_0_10px_rgba(253,224,71,0.8)] animate-pulse hidden z-10"></div>
          </div>
        ))}

        {/* Ground */}
        <div 
          className="absolute bottom-0 w-full bg-[#ded895] border-t-4 border-[#cbb968] z-20"
          style={{ height: GROUND_HEIGHT }}
        >
           <div className="w-full h-4 bg-[url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAQAAAAECAYAAACp8Z5+AAAAIklEQVQIW2NkQAKrVq36zwjjgzjIHFBMkCdYAL4YxAHLAAAYDBQz5/tq+AAAAABJRU5ErkJggg==')] opacity-30 animate-pulse"></div>
        </div>

        {/* Bird (Direct DOM) */}
        <div 
          ref={birdDomRef}
          className="absolute top-0 left-0 z-30 flex items-center justify-center will-change-transform pointer-events-none"
          style={{
            width: BIRD_SIZE,
            height: BIRD_SIZE,
            transform: `translate3d(${(GAME_WIDTH/2) - (BIRD_SIZE/2)}px, ${(GAME_HEIGHT/2)}px, 0)`
          }}
        >
          <span className="text-3xl filter drop-shadow-md">🐥</span>
        </div>

        {/* UI Layer (React) */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-40 p-4">
           {/* HUD */}
           <div className="flex justify-between items-start">
              <div>
                 <div className="flex items-baseline gap-2">
                    <span className="text-5xl font-bold pixel-text text-white drop-shadow-md leading-none">{score}</span>
                    <span className="text-sm bg-black/40 px-2 py-0.5 rounded text-white font-bold">LVL {level}</span>
                 </div>
                 {/* Hearts */}
                 <div className="flex mt-1">
                    {Array.from({length: maxHp}).map((_, i) => (
                       <span key={i} className={`text-xl ${i < currentHp ? 'grayscale-0' : 'grayscale opacity-30'}`}>❤️</span>
                    ))}
                 </div>
              </div>

              {/* Perks List */}
              <div className="flex flex-col gap-1 items-end">
                 {activePerks.map((p, i) => (
                    <div key={i} className="bg-black/40 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 backdrop-blur-sm border border-white/20">
                       <span>{p.icon}</span>
                       <span className="max-w-[80px] truncate hidden sm:inline">{p.name}</span>
                    </div>
                 ))}
              </div>
           </div>

           {/* XP Bar */}
           <div className="absolute bottom-[50px] left-4 right-4 h-2 bg-black/50 rounded-full overflow-hidden border border-white/20 max-w-3xl mx-auto">
              <div 
                 className="h-full bg-yellow-400 transition-all duration-300"
                 style={{ width: `${(xp / LEVEL_UP_XP_REQ) * 100}%` }}
              ></div>
           </div>
        </div>

        {/* Overlays */}
        {gameState === GameState.START && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-50 backdrop-blur-[2px]">
            <h1 className="text-8xl text-yellow-400 font-bold pixel-text mb-4 animate-bounce drop-shadow-[6px_6px_0_#000]">FLAPPY ROGUE</h1>
            <div className="bg-slate-900 text-white p-8 rounded-xl border-4 border-slate-700 shadow-xl text-center min-w-[300px]">
               <p className="text-2xl mb-6 font-bold animate-pulse text-yellow-200">PRESS SPACE TO START</p>
               <div className="text-lg text-slate-400 space-y-2">
                  <p>❤️ Avoid Pipes & Ground</p>
                  <p>🟡 Collect Orbs for XP</p>
                  <p>⚡ Level Up & Get Broken Perks</p>
               </div>
            </div>
          </div>
        )}

        {gameState === GameState.RESUMING && (
           <div className="absolute inset-0 flex items-center justify-center z-50 bg-black/20 backdrop-blur-[1px]">
             <span key={countdown} className="text-9xl font-bold text-white pixel-text drop-shadow-[0_0_20px_rgba(0,0,0,0.8)] animate-ping duration-75">
               {countdown}
             </span>
           </div>
        )}

        {gameState === GameState.LEVEL_UP && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-50 p-4">
             <h2 className="text-6xl text-yellow-300 font-bold pixel-text mb-8 drop-shadow-md">LEVEL {level + 1}</h2>
             <p className="text-white mb-6 text-xl">Choose a Perk:</p>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl pointer-events-auto px-6">
               {offeredPerks.map(perk => (
                 <button
                   key={perk.id}
                   onClick={() => selectPerk(perk)}
                   className={`
                     relative flex flex-col items-center justify-center text-center gap-4 p-8 rounded-xl border-b-8 active:border-b-0 active:translate-y-2 transition-all group overflow-hidden h-64
                     ${perk.rarity === 'common' ? 'bg-slate-200 border-slate-400 text-slate-900' : ''}
                     ${perk.rarity === 'rare' ? 'bg-blue-100 border-blue-400 text-blue-900' : ''}
                     ${perk.rarity === 'legendary' ? 'bg-amber-100 border-amber-400 text-amber-900' : ''}
                   `}
                 >
                   <div className="absolute right-0 top-0 opacity-10 text-9xl rotate-12 -mr-8 -mt-4 group-hover:scale-110 transition-transform">{perk.icon}</div>
                   <span className="text-6xl z-10 drop-shadow-sm mb-2">{perk.icon}</span>
                   <div className="z-10 w-full">
                     <div className="font-bold uppercase flex items-center justify-center gap-2 text-xl mb-2">
                       {perk.name}
                       <span className="text-xs px-2 py-1 bg-black/10 rounded-full font-extrabold tracking-wide uppercase">{perk.rarity}</span>
                     </div>
                     <div className="text-base opacity-90 leading-tight font-medium">{perk.description}</div>
                   </div>
                 </button>
               ))}
             </div>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-950/90 z-50 backdrop-blur-sm pointer-events-auto">
            <h2 className="text-8xl text-white font-bold pixel-text mb-4 drop-shadow-[6px_6px_0_#000]">GAME OVER</h2>

            <div className="bg-slate-100 text-slate-900 p-8 rounded-xl w-80 text-center border-8 border-slate-900 mb-8 shadow-2xl transform scale-125">
              <div className="flex justify-between mb-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Score</span>
                <span className="text-4xl font-bold">{score}</span>
              </div>
              <div className="flex justify-between border-t-4 border-slate-300 pt-4">
                <span className="text-slate-500 uppercase font-bold text-lg">Best</span>
                <span className="text-4xl font-bold text-orange-600">{Math.max(score, highScore)}</span>
              </div>
              <div className="mt-6 text-sm text-slate-400 font-mono">
                 Lvl {level} • {activePerks.length} Perks
              </div>
            </div>

            <button 
              onClick={resetGame}
              className="bg-green-500 hover:bg-green-600 text-white text-3xl font-bold py-6 px-16 rounded-2xl shadow-[0_8px_0_0_rgba(21,128,61,1)] active:shadow-none active:translate-y-2 transition-all mt-4"
            >
              RETRY
            </button>
          </div>
        )}

      </div>
    </div>
  );
};

export default GameEngine;

import { PhysicsConfig, Perk } from './types';

// Use full window dimensions
